/**
 * Host bridge interfaces for Module Federation integration.
 * Consumed by the weeklyCommit remote to receive context from the PA host app.
 */

/** Authenticated user information provided by the host. */
export interface AuthenticatedUser {
  readonly id: string;
  readonly email: string;
  readonly displayName: string;
  readonly avatarUrl?: string;
}

/** Team context provided by the host. */
export interface TeamContext {
  readonly id: string;
  readonly name: string;
  readonly parentTeamId?: string;
}

/** Environment identifier passed by the host. */
export type HostEnvironment = "development" | "staging" | "production";

/** Feature flags toggled by the host or release system. */
export interface FeatureFlags {
  readonly aiAssistanceEnabled: boolean;
  readonly managerReviewEnabled: boolean;
  readonly notificationsEnabled: boolean;
  [key: string]: boolean;
}

/**
 * Primary bridge contract between the PA host app and the weeklyCommit remote.
 * The host must supply this via the HostProvider.
 */
export interface HostContext {
  /** The currently signed-in user. */
  readonly authenticatedUser: AuthenticatedUser;
  /** The team currently in focus (may be null before selection). */
  readonly currentTeam: TeamContext | null;
  /** Ordered list of managers from direct manager up to org root. */
  readonly managerChain: readonly AuthenticatedUser[];
  /** Deployment environment. */
  readonly environment: HostEnvironment;
  /** Feature-flag map. */
  readonly featureFlags: FeatureFlags;
  /** Bearer token for API requests; refreshed by the host. */
  readonly authToken: string;
}

/**
 * CSS custom-property design tokens provided by the host.
 * The remote applies these as CSS variables on its root element.
 */
export interface DesignTokens {
  readonly colorPrimary: string;
  readonly colorSecondary: string;
  readonly colorBackground: string;
  readonly colorSurface: string;
  readonly colorText: string;
  readonly colorTextMuted: string;
  readonly colorBorder: string;
  readonly colorSuccess: string;
  readonly colorWarning: string;
  readonly colorDanger: string;
  readonly fontFamilyBase: string;
  readonly fontSizeBase: string;
  readonly borderRadius: string;
  readonly spacingUnit: string;
}

/** Callback for firing a cross-app notification (toast) via the host shell. */
export interface NotificationBridge {
  /** Show a success/info/warning/error toast in the host shell. */
  showToast(options: {
    type: "success" | "info" | "warning" | "error";
    message: string;
    durationMs?: number;
  }): void;
}

/** Telemetry callback for structured event tracking. */
export interface TelemetryCallback {
  trackEvent(eventName: string, properties?: Record<string, unknown>): void;
  trackError(error: Error, context?: Record<string, unknown>): void;
}

/** Navigation bridge for host-managed routing (cross-remote navigation). */
export interface NavigationBridge {
  /** Navigate to a path inside the host SPA (outside weeklyCommit). */
  navigateTo(path: string): void;
  /** Returns the current host-level base path prefix for the remote. */
  getBasePath(): string;
}

/*
 * Geist Mono font — loaded from CDN. In production this would come from
 * the host app's font stack or be self-hosted.
 * Must precede @import "tailwindcss" because CSS @import rules must come
 * before all other statements in the compiled output.
 */
@import url("https://fonts.googleapis.com/css2?family=Geist+Mono:wght@300..900&display=swap");

@import "tailwindcss";

/*
 * Map HostBridge DesignTokens (set as CSS custom properties by AppShell)
 * into Tailwind's theme so utilities like bg-primary, text-muted, etc. work.
 *
 * Design direction: monochrome utilitarian — Geist Mono everywhere, zero
 * radius, neutral gray primary, minimal shadow. All colors resolve through
 * CSS vars so the host app can override at runtime.
 */

@theme {
  /* ── Colors ──────────────────────────────────────────────────────── */
  --color-primary: var(--color-primary, #737373);
  --color-primary-foreground: #fafafa;
  --color-secondary: var(--color-secondary, #f5f5f5);
  --color-secondary-foreground: #171717;
  --color-surface: var(--color-surface, #ffffff);
  --color-surface-raised: #fafafa;
  --color-background: var(--color-background, #ffffff);
  --color-foreground: var(--color-text, #0a0a0a);
  --color-muted: var(--color-text-muted, #717171);
  --color-muted-bg: #f5f5f5;
  --color-border: var(--color-border, #e5e5e5);
  --color-input: #e5e5e5;
  --color-ring: #a1a1a1;
  --color-success: var(--color-success, #404040);
  --color-success-foreground: #fafafa;
  --color-warning: var(--color-warning, #737373);
  --color-warning-foreground: #fafafa;
  --color-danger: var(--color-danger, #171717);
  --color-danger-foreground: #f5f5f5;

  /* ── Typography ──────────────────────────────────────────────────── */
  --font-family-base: var(--font-family-base, "Geist Mono", ui-monospace, SFMono-Regular, "SF Mono", Menlo, Consolas, "Liberation Mono", monospace);
  --font-family-mono: "Geist Mono", ui-monospace, SFMono-Regular, "SF Mono", Menlo, Consolas, "Liberation Mono", monospace;

  /* ── Radii (0rem = sharp corners everywhere) ─────────────────────── */
  --radius-sm: calc(var(--border-radius, 0rem) * 0.75);
  --radius-default: var(--border-radius, 0rem);
  --radius-md: calc(var(--border-radius, 0rem) * 1.25);
  --radius-lg: calc(var(--border-radius, 0rem) * 2);
  --radius-full: 9999px;

  /* ── Shadows (minimal — 1px y-offset, low opacity) ───────────────── */
  --shadow-sm: 0 1px 2px 0 rgba(0, 0, 0, 0.05);
  --shadow-md: 0 1px 3px 0 rgba(0, 0, 0, 0.08);
  --shadow-lg: 0 2px 8px 0 rgba(0, 0, 0, 0.08);
}

/*
 * ── Dark mode ─────────────────────────────────────────────────────────
 *
 * Activated by <html data-theme="dark">. Every semantic color is remapped;
 * components pick up the change automatically through CSS vars.
 * The palette is the same neutral gray family, just inverted.
 */

@layer base {
  [data-theme="dark"] {
    --color-primary: #a3a3a3;
    --color-primary-foreground: #0a0a0a;
    --color-secondary: #1c1c1c;
    --color-secondary-foreground: #e5e5e5;
    --color-surface: #141414;
    --color-surface-raised: #1c1c1c;
    --color-background: #0a0a0a;
    --color-foreground: #e5e5e5;
    --color-text: #e5e5e5;
    --color-muted: #737373;
    --color-text-muted: #737373;
    --color-muted-bg: #1c1c1c;
    --color-border: #2a2a2a;
    --color-input: #2a2a2a;
    --color-ring: #525252;
    --color-success: #4ade80;
    --color-success-foreground: #0a0a0a;
    --color-warning: #fbbf24;
    --color-warning-foreground: #0a0a0a;
    --color-danger: #f87171;
    --color-danger-foreground: #0a0a0a;

    --shadow-sm: 0 1px 2px 0 rgba(0, 0, 0, 0.3);
    --shadow-md: 0 1px 3px 0 rgba(0, 0, 0, 0.4);
    --shadow-lg: 0 2px 8px 0 rgba(0, 0, 0, 0.5);

    color-scheme: dark;
  }
}

/* ── Base resets ─────────────────────────────────────────────────────── */

@layer base {
  html {
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
  }

  body {
    font-family: var(--font-family-base);
    color: var(--color-foreground);
    background: var(--color-background);
    font-feature-settings: "ss01", "ss02", "cv01";
  }

  /* Accessible focus ring — uses the ring color token */
  :focus-visible {
    outline: 2px solid var(--color-ring);
    outline-offset: 2px;
  }

  /* Remove default focus for mouse users */
  :focus:not(:focus-visible) {
    outline: none;
  }

  .visually-hidden {
    position: absolute;
    width: 1px;
    height: 1px;
    padding: 0;
    margin: -1px;
    overflow: hidden;
    clip: rect(0, 0, 0, 0);
    white-space: nowrap;
    border: 0;
  }
}

/* ── Scrollbar styling ───────────────────────────────────────────────── */

@layer base {
  ::-webkit-scrollbar {
    width: 6px;
    height: 6px;
  }
  ::-webkit-scrollbar-track {
    background: transparent;
  }
  ::-webkit-scrollbar-thumb {
    background: var(--color-border);
    border-radius: var(--radius-full);
    transition: background 0.2s;
  }
  ::-webkit-scrollbar-thumb:hover {
    background: var(--color-muted);
  }
}

/* ── Theme transition ────────────────────────────────────────────────── */

@layer base {
  [data-theme] {
    transition: background-color 0.2s ease, color 0.2s ease, border-color 0.2s ease;
  }
}

/* ── Chess piece shade tokens ─────────────────────────────────────────
 * Used by Reports, ChessDistributionSection, and AnswerRenderer via
 * var(--chess-king) etc. Flip to light shades in dark mode so the
 * gradient still reads darkest=KING → lightest=PAWN relative to bg.
 */

@layer base {
  :root {
    --chess-king: #0a0a0a;
    --chess-queen: #262626;
    --chess-rook: #525252;
    --chess-bishop: #737373;
    --chess-knight: #a3a3a3;
    --chess-pawn: #d4d4d4;
  }
  [data-theme="dark"] {
    --chess-king: #f5f5f5;
    --chess-queen: #d4d4d4;
    --chess-rook: #a3a3a3;
    --chess-bishop: #737373;
    --chess-knight: #525252;
    --chess-pawn: #2a2a2a;
  }
}

/* ── Transitions ─────────────────────────────────────────────────────── */

@layer utilities {
  .transition-sidebar {
    transition: width 200ms ease-in-out, padding 200ms ease-in-out;
  }
}

/**
 * App shell — polished sidebar + header + content layout.
 * Applies design tokens as CSS custom properties on the root element.
 * Sidebar is collapsible with state persisted to localStorage.
 */
import { type ReactNode, useState, useEffect } from "react";
import type { DesignTokens } from "@weekly-commit/shared";
import { useHostBridge } from "../host/HostProvider.js";
import { Navigation } from "./Navigation.js";
import { Header, getWeekMonday } from "./Header.js";
import { cn } from "../lib/utils.js";
import { useTheme } from "../lib/useTheme.js";

interface AppShellProps {
  readonly children: ReactNode;
}

const SIDEBAR_KEY = "wc-sidebar-collapsed";

/**
 * Converts DesignTokens into CSS custom properties.
 *
 * When dark mode is active, color tokens are omitted so the CSS
 * [data-theme="dark"] overrides in index.css take effect. Non-color
 * tokens (font, spacing, radius) always apply.
 */
function tokensToStyle(
  tokens: DesignTokens,
  isDark: boolean,
): React.CSSProperties {
  const base: Record<string, string> = {
    "--font-family-base": tokens.fontFamilyBase,
    "--font-size-base": tokens.fontSizeBase,
    "--border-radius": tokens.borderRadius,
    "--spacing-unit": tokens.spacingUnit,
  };

  if (!isDark) {
    // In light mode (or host-provided), apply color tokens as inline vars
    // so the host app's palette overrides our CSS defaults.
    Object.assign(base, {
      "--color-primary": tokens.colorPrimary,
      "--color-secondary": tokens.colorSecondary,
      "--color-background": tokens.colorBackground,
      "--color-surface": tokens.colorSurface,
      "--color-text": tokens.colorText,
      "--color-text-muted": tokens.colorTextMuted,
      "--color-border": tokens.colorBorder,
      "--color-success": tokens.colorSuccess,
      "--color-warning": tokens.colorWarning,
      "--color-danger": tokens.colorDanger,
    });
  }

  return base as React.CSSProperties;
}

export function AppShell({ children }: AppShellProps) {
  const { tokens } = useHostBridge();
  const { resolved } = useTheme();
  const isDark = resolved === "dark";
  const [selectedWeek, setSelectedWeek] = useState(() =>
    getWeekMonday(new Date()),
  );
  const [collapsed, setCollapsed] = useState(() => {
    try {
      return localStorage.getItem(SIDEBAR_KEY) === "true";
    } catch {
      return false;
    }
  });

  useEffect(() => {
    try {
      localStorage.setItem(SIDEBAR_KEY, String(collapsed));
    } catch {
      // ignore
    }
  }, [collapsed]);

  return (
    <div
      className="flex h-screen flex-col overflow-hidden bg-background text-foreground"
      style={{
        ...tokensToStyle(tokens, isDark),
        fontFamily: "var(--font-family-base)",
        fontSize: "var(--font-size-base)",
      }}
      data-testid="app-shell"
    >
      {/* Header */}
      <Header
        selectedWeek={selectedWeek}
        onWeekChange={setSelectedWeek}
        collapsed={collapsed}
        onToggleSidebar={() => setCollapsed((c) => !c)}
      />

      {/* Body: sidebar + main */}
      <div className="flex flex-1 overflow-hidden">
        {/* Sidebar */}
        <aside
          className={cn(
            "flex shrink-0 flex-col border-r border-border bg-surface transition-sidebar overflow-y-auto overflow-x-hidden",
            collapsed ? "w-14 px-1.5 py-4" : "w-56 px-3 py-4",
          )}
          aria-label="Sidebar"
        >
          {/* Brand mark in sidebar — visible when expanded */}
          {!collapsed && (
            <div className="mb-6 px-3">
              <p className="text-[10px] font-semibold uppercase tracking-widest text-muted">
                Navigation
              </p>
            </div>
          )}

          <Navigation collapsed={collapsed} />

          {/* Spacer pushes bottom content down */}
          <div className="flex-1" />

          {/* Version or help link at bottom */}
          {!collapsed && (
            <div className="mt-4 px-3 pt-4 border-t border-border">
              <p className="text-[10px] text-muted">v1.0.0</p>
            </div>
          )}
        </aside>

        {/* Main content */}
        <main
          className="flex-1 overflow-auto p-6"
          role="main"
        >
          {children}
        </main>
      </div>
    </div>
  );
}

import type { ReactNode } from "react";
import type {
  HostContext,
  DesignTokens,
  NotificationBridge,
  TelemetryCallback,
  NavigationBridge,
} from "@weekly-commit/shared";
import { HostProvider, type HostBridge } from "./HostProvider.js";

/**
 * Default design tokens for standalone development (maps to CSS custom props).
 *
 * Design direction: monochrome utilitarian — Geist Mono everywhere, zero
 * radius, neutral gray primary, minimal shadow. Inspired by shadcn/ui
 * "New York" neutral theme.
 */
export const defaultDesignTokens: DesignTokens = {
  colorPrimary: "#737373",
  colorSecondary: "#f5f5f5",
  colorBackground: "#ffffff",
  colorSurface: "#ffffff",
  colorText: "#0a0a0a",
  colorTextMuted: "#717171",
  colorBorder: "#e5e5e5",
  colorSuccess: "#16a34a",
  colorWarning: "#d97706",
  colorDanger: "#e7000b",
  fontFamilyBase:
    "'Geist Mono', ui-monospace, SFMono-Regular, 'SF Mono', Menlo, Consolas, 'Liberation Mono', monospace",
  fontSizeBase: "16px",
  borderRadius: "0px",
  spacingUnit: "8px",
};

/** Mock host context used during standalone dev and unit tests. */
export const mockHostContext: HostContext = {
  authenticatedUser: {
    id: "00000000-0000-0000-0000-000000000001",
    email: "dev@example.com",
    displayName: "Dev User",
  },
  currentTeam: {
    id: "00000000-0000-0000-0000-000000000010",
    name: "Engineering",
  },
  managerChain: [
    {
      id: "00000000-0000-0000-0000-000000000002",
      email: "manager@example.com",
      displayName: "Manager One",
    },
  ],
  environment: "development",
  featureFlags: {
    aiAssistanceEnabled: true,
    managerReviewEnabled: true,
    notificationsEnabled: true,
    rcdoAdminEnabled: true,
  },
  authToken: "mock-dev-token",
};

const mockNotifications: NotificationBridge = {
  showToast({ type, message }) {
    // In dev mode, log toasts to the console
    console.info(`[toast:${type}] ${message}`);
  },
};

const mockTelemetry: TelemetryCallback = {
  trackEvent(eventName, properties) {
    console.debug("[telemetry:event]", eventName, properties);
  },
  trackError(error, context) {
    console.error("[telemetry:error]", error, context);
  },
};

const mockNavigation: NavigationBridge = {
  navigateTo(path) {
    console.info("[navigation:navigateTo]", path);
  },
  getBasePath() {
    return "/weekly";
  },
};

export const mockHostBridge: HostBridge = {
  context: mockHostContext,
  tokens: defaultDesignTokens,
  notifications: mockNotifications,
  telemetry: mockTelemetry,
  navigation: mockNavigation,
};

interface MockHostProviderProps {
  readonly bridge?: HostBridge;
  readonly children: ReactNode;
}

/**
 * Drop-in replacement for HostProvider in standalone dev mode and unit tests.
 * Passes sensible mock data for all host bridge contracts.
 */
export function MockHostProvider({
  bridge = mockHostBridge,
  children,
}: MockHostProviderProps) {
  return <HostProvider bridge={bridge}>{children}</HostProvider>;
}

import { type HTMLAttributes } from "react";
import { cva, type VariantProps } from "class-variance-authority";
import { cn } from "../../lib/utils.js";

/**
 * Badge variants — monochrome palette with subtle tonal shifts for
 * semantic meaning. Uses px-based rounding (not rounded-full) so badges
 * pick up the global radius token. Plan-state badges use gray-scale tints
 * to stay within the neutral design direction.
 */
const badgeVariants = cva(
  "inline-flex items-center rounded-sm border px-2.5 py-0.5 text-xs font-semibold tracking-wide transition-colors",
  {
    variants: {
      variant: {
        default: "border-border bg-muted-bg text-foreground",
        primary: "border-foreground/20 bg-foreground/5 text-foreground",
        success: "border-foreground/25 bg-foreground/5 text-foreground",
        warning: "border-foreground/15 bg-foreground/[0.03] text-muted",
        danger: "border-foreground/30 bg-foreground/8 text-foreground font-bold",
        /* Plan-state badges: monochrome tonal variations */
        draft: "border-border bg-muted-bg text-muted",
        locked: "border-foreground/20 bg-foreground/5 text-foreground",
        reconciling: "border-foreground/15 bg-foreground/[0.03] text-muted",
        reconciled: "border-foreground/25 bg-foreground/5 text-foreground",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  },
);

export interface BadgeProps
  extends HTMLAttributes<HTMLSpanElement>,
    VariantProps<typeof badgeVariants> {}

function Badge({ className, variant, ...props }: BadgeProps) {
  return (
    <span className={cn(badgeVariants({ variant, className }))} {...props} />
  );
}

export { Badge, badgeVariants };

import { forwardRef, type ButtonHTMLAttributes } from "react";
import { cva, type VariantProps } from "class-variance-authority";
import { cn } from "../../lib/utils.js";

/**
 * Button variants — monochrome design system.
 * Primary uses the neutral gray (#737373) with white foreground.
 * All corners are sharp (radius comes from the global token = 0).
 */
const buttonVariants = cva(
  "inline-flex items-center justify-center gap-2 whitespace-nowrap font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring/50 disabled:pointer-events-none disabled:opacity-50",
  {
    variants: {
      variant: {
        primary:
          "bg-foreground text-primary-foreground shadow-sm hover:bg-foreground/90 active:bg-foreground/80",
        secondary:
          "border border-border bg-surface text-foreground shadow-sm hover:bg-muted-bg active:bg-muted-bg/80",
        ghost:
          "text-foreground hover:bg-muted-bg active:bg-muted-bg/80",
        danger:
          "bg-danger text-danger-foreground shadow-sm hover:bg-danger/90 active:bg-danger/80",
        success:
          "bg-success text-success-foreground shadow-sm hover:bg-success/90 active:bg-success/80",
        link:
          "text-foreground underline-offset-4 hover:underline p-0 h-auto",
      },
      size: {
        sm: "h-8 rounded-sm px-3 text-xs",
        md: "h-9 rounded-default px-4 text-sm",
        lg: "h-10 rounded-md px-5 text-sm",
        icon: "h-9 w-9 rounded-default",
      },
    },
    defaultVariants: {
      variant: "primary",
      size: "md",
    },
  },
);

export interface ButtonProps
  extends ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {}

const Button = forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant, size, ...props }, ref) => (
    <button
      ref={ref}
      className={cn(buttonVariants({ variant, size, className }))}
      {...props}
    />
  ),
);
Button.displayName = "Button";

export { Button, buttonVariants };

/**
 * Toast notification system.
 * Can be driven by the HostBridge NotificationBridge or used standalone.
 */
import { useState, useCallback, createContext, useContext, type ReactNode } from "react";
import { cva } from "class-variance-authority";
import { cn } from "../../lib/utils.js";
import { X } from "lucide-react";

/* ── Toast Variant Styles ──────────────────────────────────────────── */

const toastVariants = cva(
  "pointer-events-auto flex items-center gap-3 rounded-default border px-4 py-3 text-sm shadow-lg transition-all",
  {
    variants: {
      type: {
        success: "border-success/30 bg-success/10 text-success",
        info: "border-primary/30 bg-primary/10 text-primary",
        warning: "border-warning/30 bg-warning/10 text-warning",
        error: "border-danger/30 bg-danger/10 text-danger",
      },
    },
    defaultVariants: { type: "info" },
  },
);

/* ── Types ─────────────────────────────────────────────────────────── */

interface ToastItem {
  id: string;
  type: "success" | "info" | "warning" | "error";
  message: string;
}

interface ToastContextValue {
  showToast(options: {
    type: "success" | "info" | "warning" | "error";
    message: string;
    durationMs?: number;
  }): void;
}

/* ── Context ───────────────────────────────────────────────────────── */

const ToastContext = createContext<ToastContextValue | null>(null);

function useToast(): ToastContextValue {
  const ctx = useContext(ToastContext);
  if (!ctx) throw new Error("useToast must be used within <ToastProvider>");
  return ctx;
}

/* ── Provider ──────────────────────────────────────────────────────── */

let toastCounter = 0;

function ToastProvider({ children }: { children: ReactNode }) {
  const [toasts, setToasts] = useState<ToastItem[]>([]);

  const showToast = useCallback(
    (options: {
      type: "success" | "info" | "warning" | "error";
      message: string;
      durationMs?: number;
    }) => {
      const id = `toast-${++toastCounter}`;
      setToasts((prev) => [...prev, { id, type: options.type, message: options.message }]);
      setTimeout(() => {
        setToasts((prev) => prev.filter((t) => t.id !== id));
      }, options.durationMs ?? 4000);
    },
    [],
  );

  const dismiss = useCallback((id: string) => {
    setToasts((prev) => prev.filter((t) => t.id !== id));
  }, []);

  return (
    <ToastContext.Provider value={{ showToast }}>
      {children}
      {/* Toast container */}
      <div
        aria-live="polite"
        className="pointer-events-none fixed bottom-4 right-4 z-[100] flex flex-col gap-2"
      >
        {toasts.map((t) => (
          <div key={t.id} className={cn(toastVariants({ type: t.type }))}>
            <span className="flex-1">{t.message}</span>
            <button
              type="button"
              onClick={() => dismiss(t.id)}
              className="pointer-events-auto rounded-sm p-0.5 opacity-70 hover:opacity-100"
              aria-label="Dismiss"
            >
              <X className="h-3.5 w-3.5" />
            </button>
          </div>
        ))}
      </div>
    </ToastContext.Provider>
  );
}

export { ToastProvider, useToast, toastVariants };

/**
 * My Week — personal weekly plan view.
 * Route: /weekly/my-week
 */
import { useState, useCallback, useMemo, Component, type ErrorInfo, type ReactNode } from "react";
import { Link } from "react-router-dom";
import { ChevronLeft, ChevronRight, Lock, AlertTriangle, Check, X, ArrowRight, Sparkles } from "lucide-react";
import { Button } from "../components/ui/Button.js";
import { Badge } from "../components/ui/Badge.js";
import { Card, CardHeader, CardTitle, CardContent } from "../components/ui/Card.js";
import { Dialog, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from "../components/ui/Dialog.js";
import { useCurrentPlan, usePlanApi } from "../api/planHooks.js";
import { useRcdoTree } from "../api/rcdoHooks.js";
import { usePlanHistory, useCarryForwardLineage, useTicketApi } from "../api/ticketHooks.js";
import { PlanHistoryView } from "../components/myweek/PlanHistoryView.js";
import { CarryForwardLineageView } from "../components/myweek/CarryForwardLineageView.js";
import { TicketForm } from "../components/tickets/TicketForm.js";
import { useHostBridge } from "../host/HostProvider.js";
import type { CreateTicketPayload } from "../api/ticketTypes.js";
import { CommitList } from "../components/myweek/CommitList.js";
import { CommitForm } from "../components/myweek/CommitForm.js";
import { CapacityMeter } from "../components/myweek/CapacityMeter.js";
import { SoftWarningsPanel } from "../components/myweek/SoftWarningsPanel.js";
import { PreLockValidationPanel } from "../components/lock/PreLockValidationPanel.js";
import { LockConfirmDialog } from "../components/lock/LockConfirmDialog.js";
import { ScopeChangeDialog } from "../components/lock/ScopeChangeDialog.js";
import { ScopeChangeTimeline } from "../components/lock/ScopeChangeTimeline.js";
import { getEffectivePreLockErrors } from "../components/lock/lockValidation.js";
import { InsightPanel } from "../components/ai/InsightPanel.js";
import { AiLintPanel } from "../components/ai/AiLintPanel.js";
import { AiCommitComposer } from "../components/ai/AiCommitComposer.js";
import { ProactiveRiskBanner } from "../components/ai/ProactiveRiskBanner.js";
import { WhatIfPanel } from "../components/ai/WhatIfPanel.js";
