import { useState, useEffect, useMemo, useCallback } from "react";
import {
  BarChart3,
  TrendingUp,
  TrendingDown,
  RotateCcw,
  Shield,
  Brain,
  AlertTriangle,
  ChevronLeft,
  ChevronRight,
  Activity,
  Target,
  Zap,
