/**
 * React hooks for Plan and Commit data fetching.
 * Builds an ApiClient from the host bridge and delegates to planApi.
 */

import { useMemo } from "react";
import { useHostBridge } from "../host/HostProvider.js";
import { createApiClient } from "./client.js";
import { useQuery, type QueryState } from "./hooks.js";
import { createPlanApi, type PlanApi } from "./planApi.js";
import type { PlanWithCommitsResponse } from "./planTypes.js";

/**
 * Returns a stable PlanApi instance bound to the current user's auth token.
 * Re-creates the API object only when the authToken or userId changes.
 */
export function usePlanApi(): PlanApi {
  const bridge = useHostBridge();
  const { authToken, authenticatedUser } = bridge.context;
  return useMemo(
    () => {
      const client = createApiClient({
        baseUrl: "/api",
        getAuthToken: () => bridge.context.authToken,
      });
      return createPlanApi(client, authenticatedUser.id);
    },
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [authToken, authenticatedUser.id],
  );
}

/**
 * Fetches (or creates) the weekly plan for the authenticated user.
 * Pass a weekStartDate (yyyy-MM-dd) to view a specific week; omit for current week.
 */
export function useCurrentPlan(
  weekStartDate?: string,
): QueryState<PlanWithCommitsResponse> {
  const api = usePlanApi();
  const bridge = useHostBridge();
  const userId = bridge.context.authenticatedUser.id;
  const key = `plan-${userId}-${weekStartDate ?? "current"}`;
  return useQuery<PlanWithCommitsResponse>(key, () =>
    api.getOrCreatePlan(userId, weekStartDate),
  );
}

/**
 * Plan and Commit API call functions built on top of the generic ApiClient.
 * Each function maps to one backend endpoint in PlanController.
 */

import type { ApiClient } from "./client.js";
import type {
  PlanWithCommitsResponse,
  CreateCommitPayload,
  UpdateCommitPayload,
  CommitResponse,
  LockResponse,
  ScopeChangePayload,
  ScopeChangeTimelineResponse,
  ReconciliationViewResponse,
  SetOutcomePayload,
  CarryForwardPayload,
} from "./planTypes.js";

export function createPlanApi(client: ApiClient, actorUserId: string) {
  const actorHeader = { "X-Actor-User-Id": actorUserId };

  return {
    /**
     * POST /api/plans — get-or-create the plan for a user + optional week.
     * If weekStartDate is omitted, the backend uses the current Monday.
     */
    getOrCreatePlan: (
      userId: string,
      weekStartDate?: string,
    ): Promise<PlanWithCommitsResponse> =>
      client.post("/plans", {
        userId,
        ...(weekStartDate ? { weekStartDate } : {}),
      }),

    /** GET /api/plans/{id} — plan detail with commits in priority order. */
    getPlan: (planId: string): Promise<PlanWithCommitsResponse> =>
      client.get(`/plans/${encodeURIComponent(planId)}`),

    /** POST /api/plans/{planId}/commits — create a commit on a DRAFT plan. */
    createCommit: (
      planId: string,
      payload: CreateCommitPayload,
    ): Promise<CommitResponse> =>
      client.post(
        `/plans/${encodeURIComponent(planId)}/commits`,
        payload,
        { headers: actorHeader },
      ),

    /** PUT /api/plans/{planId}/commits/{commitId} — update mutable commit fields. */
    updateCommit: (
      planId: string,
      commitId: string,
      payload: UpdateCommitPayload,
    ): Promise<CommitResponse> =>
      client.put(
        `/plans/${encodeURIComponent(planId)}/commits/${encodeURIComponent(commitId)}`,
        payload,
        { headers: actorHeader },
      ),

    /** DELETE /api/plans/{planId}/commits/{commitId} — delete a commit. */
    deleteCommit: (planId: string, commitId: string): Promise<void> =>
      client.delete(
        `/plans/${encodeURIComponent(planId)}/commits/${encodeURIComponent(commitId)}`,
        { headers: actorHeader },
      ),

    /**
     * PUT /api/plans/{planId}/commits/reorder — reorder commits by supplying
     * all commit IDs in the desired priority order.
     */
    reorderCommits: (
      planId: string,
      commitIds: string[],
    ): Promise<PlanWithCommitsResponse> =>
      client.put(
        `/plans/${encodeURIComponent(planId)}/commits/reorder`,
        { commitIds },
        { headers: actorHeader },
      ),

    /**
     * POST /api/plans/{id}/lock — manually lock a DRAFT plan.
     * Returns LockResponse: success=true with locked plan, or success=false
     * with validation errors that block the lock.
     */
    lockPlan: (planId: string): Promise<LockResponse> =>
      client.post(
        `/plans/${encodeURIComponent(planId)}/lock`,
        {},
        { headers: actorHeader },
      ),

    // ── Post-lock scope changes ──────────────────────────────────────────────

    /**
     * POST /api/plans/{id}/scope-changes — apply a post-lock scope change.
     * Action = ADD | REMOVE | EDIT, each with required fields in the payload.
     */
    applyScopeChange: (
      planId: string,
      payload: ScopeChangePayload,
    ): Promise<ScopeChangeTimelineResponse> =>
      client.post(
        `/plans/${encodeURIComponent(planId)}/scope-changes`,
        payload,
        { headers: actorHeader },
      ),

    /** GET /api/plans/{id}/scope-changes — chronological scope-change timeline. */
    getScopeChangeTimeline: (
      planId: string,
    ): Promise<ScopeChangeTimelineResponse> =>
      client.get(`/plans/${encodeURIComponent(planId)}/scope-changes`),

    // ── Reconciliation ───────────────────────────────────────────────────────

    /**
     * POST /api/plans/{id}/reconcile/open — transition LOCKED → RECONCILING.
     * Idempotent; returns the reconciliation view immediately.
     */
    openReconciliation: (planId: string): Promise<ReconciliationViewResponse> =>
      client.post(
        `/plans/${encodeURIComponent(planId)}/reconcile/open`,
        {},
        { headers: actorHeader },
      ),

    /** GET /api/plans/{id}/reconcile — reconciliation view (RECONCILING or RECONCILED). */
    getReconciliationView: (
      planId: string,
    ): Promise<ReconciliationViewResponse> =>
      client.get(`/plans/${encodeURIComponent(planId)}/reconcile`),

    /** PUT /api/plans/{id}/commits/{commitId}/outcome — set outcome for a commit. */
    setCommitOutcome: (
      planId: string,
      commitId: string,
      payload: SetOutcomePayload,
    ): Promise<CommitResponse> =>
      client.put(
        `/plans/${encodeURIComponent(planId)}/commits/${encodeURIComponent(commitId)}/outcome`,
        payload,
        { headers: actorHeader },
      ),

    /** POST /api/plans/{id}/reconcile/submit — submit (finalise) reconciliation. */
    submitReconciliation: (
      planId: string,
    ): Promise<ReconciliationViewResponse> =>
      client.post(
        `/plans/${encodeURIComponent(planId)}/reconcile/submit`,
        {},
        { headers: actorHeader },
      ),

    // ── Carry forward ────────────────────────────────────────────────────────

    /**
     * POST /api/plans/{planId}/commits/{commitId}/carry-forward
     * Creates a copy of the commit in the target week plan.
     */
    carryForward: (
      planId: string,
      commitId: string,
      payload: CarryForwardPayload,
    ): Promise<unknown> =>
      client.post(
        `/plans/${encodeURIComponent(planId)}/commits/${encodeURIComponent(commitId)}/carry-forward`,
        payload,
        { headers: actorHeader },
      ),
  };
}

export type PlanApi = ReturnType<typeof createPlanApi>;

/**
 * SoftWarningsPanel — UI-only soft warnings, never lock blockers.
 */
import { AlertTriangle } from "lucide-react";
import type { CommitResponse } from "../../api/planTypes.js";

const SOFT_MAX_COMMITS = 8;
const PAWN_POINT_WARNING_THRESHOLD = 0.4;

export interface SoftWarningsPanelProps {
  readonly commits: CommitResponse[];
}

export function SoftWarningsPanel({ commits }: SoftWarningsPanelProps) {
  const activeCommits = commits.filter((c) => c.outcome == null);
  const totalPoints = commits.reduce((sum, c) => sum + (c.estimatePoints ?? 0), 0);
  const pawnPoints = commits.filter((c) => c.chessPiece === "PAWN").reduce((sum, c) => sum + (c.estimatePoints ?? 0), 0);

  const tooManyCommits = activeCommits.length > SOFT_MAX_COMMITS;
  const tooManyPawns = totalPoints > 0 && pawnPoints / totalPoints > PAWN_POINT_WARNING_THRESHOLD;

  if (!tooManyCommits && !tooManyPawns) return null;

  return (
    <div data-testid="soft-warnings-panel" aria-live="polite" className="flex flex-col gap-2">
      {tooManyCommits && (
        <div
          role="status"
          data-testid="warning-too-many-commits"
          className="flex items-start gap-2 px-3 py-2.5 rounded-default border border-neutral-300 bg-neutral-100 text-sm text-foreground"
        >
          <AlertTriangle className="h-4 w-4 shrink-0 mt-0.5 text-neutral-500" aria-hidden="true" />
          <span>
            <strong>Too many commits:</strong> you have {activeCommits.length} active commits. Consider focusing on
            fewer items for better weekly throughput (recommended: ≤{SOFT_MAX_COMMITS}).
          </span>
        </div>
      )}

      {tooManyPawns && (
        <div
          role="status"
          data-testid="warning-pawn-heavy"
          className="flex items-start gap-2 px-3 py-2.5 rounded-default border border-neutral-300 bg-neutral-100 text-sm text-foreground"
        >
          <AlertTriangle className="h-4 w-4 shrink-0 mt-0.5 text-neutral-500" aria-hidden="true" />
          <span>
            <strong>Pawn-heavy plan:</strong> {Math.round((pawnPoints / totalPoints) * 100)}% of your points are Pawn
            commits. Consider elevating strategic work.
          </span>
        </div>
      )}
    </div>
  );
}

/**
 * AI commit lint panel — replaces the placeholder in PreLockValidationPanel.
 * Calls POST /api/ai/commit-lint and displays hard + soft lint messages
 * with feedback buttons on each.
 *
 * When `autoRun` is true the lint API is called automatically on mount and
 * whenever `planId` changes — no button click required.  The manual refresh
 * button is still shown inside the results view so users can re-run after
 * editing commits.
 */
import { useState, useCallback, useEffect, useRef } from "react";
import { Bot, RefreshCw } from "lucide-react";
import { Button } from "../ui/Button.js";
import { AiFeedbackButtons } from "./AiFeedbackButtons.js";
import { useAiApi, useAiStatus } from "../../api/aiHooks.js";
import type { CommitLintResponse } from "../../api/aiApi.js";

interface AiLintPanelProps {
  planId: string;
  userId: string;
  /** When true, lint fires automatically on mount and on planId change (no button click required). */
  autoRun?: boolean;
  /**
   * Monotonically increasing counter. Every time this value changes the lint
   * re-fires (debounced). Callers should increment it after any commit
   * create / edit / delete / reorder operation so lint results stay current.
   */
  refreshKey?: number;
}

export function AiLintPanel({ planId, userId, autoRun = false, refreshKey = 0 }: AiLintPanelProps) {
  const aiApi = useAiApi();
  const { data: status } = useAiStatus();
  const [lintResult, setLintResult] = useState<CommitLintResponse | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const isAvailable = status?.available ?? false;

  const runLint = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const result = await aiApi.commitLint({ userId, planId });
      setLintResult(result);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Lint failed");
    } finally {
      setLoading(false);
    }
  }, [aiApi, planId, userId]);

  // Auto-run: fire lint on mount (and whenever planId changes) when AI is available.
  // Guard on isAvailable so we don't kick off a doomed request when AI is down.
  useEffect(() => {
    if (!autoRun || !isAvailable) return;
    void runLint();
  }, [autoRun, planId, isAvailable, runLint]);

  // Re-run with debounce when refreshKey changes (after commit CRUD operations).
  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const prevRefreshKeyRef = useRef(refreshKey);
  useEffect(() => {
    // Skip the initial mount — the effect above already covers that.
    if (refreshKey === prevRefreshKeyRef.current) return;
    prevRefreshKeyRef.current = refreshKey;
    if (!autoRun || !isAvailable) return;

    if (debounceRef.current) clearTimeout(debounceRef.current);
    debounceRef.current = setTimeout(() => {
      void runLint();
    }, 800);

    return () => {
      if (debounceRef.current) clearTimeout(debounceRef.current);
    };
  }, [refreshKey, autoRun, isAvailable, runLint]);

  // AI not available — show disabled state
  if (status && !status.available) {
    return (
      <div className="flex items-center gap-2 rounded-default border border-dashed border-border bg-background/60 px-3 py-2.5 text-xs text-muted italic" data-testid="ai-lint-unavailable">
        <Bot className="h-3.5 w-3.5 shrink-0" aria-hidden="true" />
        AI commit quality hints unavailable ({status.providerName})
      </div>
    );
  }

  // Not yet run:
  //   - autoRun=false  → show the manual trigger button
  //   - autoRun=true   → lint is about to fire (or waiting for status); render nothing
  //                       so there is no flash of a button that immediately disappears
  if (!lintResult && !loading) {
    if (autoRun) {
      return null;
    }
    return (
      <div className="flex items-center gap-2" data-testid="ai-lint-ready">
        <Button variant="ghost" size="sm" onClick={() => void runLint()} className="h-7 text-xs border border-dashed border-border" data-testid="ai-lint-run-btn">
          <Bot className="h-3.5 w-3.5" />
          Run AI Quality Check
        </Button>
      </div>
    );
  }

  // Loading
  if (loading) {
    return (
      <div className="flex items-center gap-2 text-xs text-muted animate-pulse" data-testid="ai-lint-loading">
        <Bot className="h-3.5 w-3.5 shrink-0" />
        Analyzing commit quality…
      </div>
    );
  }

  // Error
  if (error) {
    return (
      <div className="flex items-center gap-2 text-xs text-danger" data-testid="ai-lint-error">
        <Bot className="h-3.5 w-3.5 shrink-0" />
        {error}
        <Button variant="ghost" size="sm" onClick={() => void runLint()} className="h-6 text-xs">
          <RefreshCw className="h-3 w-3" />Retry
        </Button>
      </div>
    );
  }

  // Results
  if (!lintResult?.aiAvailable) {
    return (
      <div className="text-xs text-muted italic" data-testid="ai-lint-unavailable">
        <Bot className="h-3.5 w-3.5 inline mr-1" />AI lint unavailable
      </div>
    );
  }

  const hasHard = lintResult.hardValidation.length > 0;
  const hasSoft = lintResult.softGuidance.length > 0;

  return (
    <div className="flex flex-col gap-2" data-testid="ai-lint-results">
      {/* Header with refresh */}
      <div className="flex items-center justify-between">
        <span className="flex items-center gap-1.5 text-xs font-semibold text-muted">
          <Bot className="h-3.5 w-3.5" />AI Quality Check
        </span>
        <div className="flex items-center gap-1.5">
          {lintResult.suggestionId && <AiFeedbackButtons suggestionId={lintResult.suggestionId} />}
          <Button variant="ghost" size="sm" onClick={() => void runLint()} className="h-6 text-xs" data-testid="ai-lint-refresh">
            <RefreshCw className="h-3 w-3" />
          </Button>
        </div>
      </div>

      {/* Hard validations */}
      {hasHard && (
        <div className="rounded-sm border border-neutral-300 bg-neutral-100 px-3 py-2" data-testid="ai-lint-hard">
          <p className="m-0 mb-1 text-xs font-bold text-foreground underline">Hard Issues</p>
          <ul className="m-0 pl-4 flex flex-col gap-0.5">
            {lintResult.hardValidation.map((msg, i) => (
              <li key={i} className="text-xs text-foreground">{msg.message}</li>
            ))}
          </ul>
        </div>
      )}

      {/* Soft guidance */}
      {hasSoft && (
        <div className="rounded-sm border border-neutral-200 bg-neutral-50 px-3 py-2" data-testid="ai-lint-soft">
          <p className="m-0 mb-1 text-xs font-semibold text-muted">Suggestions</p>
          <ul className="m-0 pl-4 flex flex-col gap-0.5">
            {lintResult.softGuidance.map((msg, i) => (
              <li key={i} className="text-xs text-muted">{msg.message}</li>
            ))}
          </ul>
        </div>
      )}

      {/* All clear */}
      {!hasHard && !hasSoft && (
        <div className="text-xs text-foreground flex items-center gap-1" data-testid="ai-lint-clear">
          ✓ No quality issues detected
        </div>
      )}
    </div>
  );
}

/**
 * WhatIfPanel — interactive what-if planner for hypothetical commit mutations.
 *
 * Lets users queue ADD / REMOVE / MODIFY mutations, simulate their impact
 * against the plan (always deterministic) and optionally view an AI narrative
 * (shown only when narrative is non-null — degrades gracefully when AI is down).
 *
 * Important: this panel does NOT gate on AI availability — the simulation is
 * backend rule-based logic that works without a live LLM.
 */
import { useState, useCallback } from "react";
import { Sparkles, Loader2, ChevronUp, Plus, X } from "lucide-react";
import { Button } from "../ui/Button.js";
import { Badge } from "../ui/Badge.js";
import { Card, CardContent, CardHeader, CardTitle } from "../ui/Card.js";
import { cn } from "../../lib/utils.js";
import { useWhatIfApi } from "../../api/aiHooks.js";
import { useHostBridge } from "../../host/HostProvider.js";
import type { CommitResponse } from "../../api/planTypes.js";
import type {
  WhatIfMutation,
  WhatIfMutationAction,
  WhatIfResponse,
} from "../../api/whatIfApi.js";

// ── Constants ─────────────────────────────────────────────────────────────────

const CHESS_PIECES = ["KING", "QUEEN", "ROOK", "BISHOP", "KNIGHT", "PAWN"] as const;
const ESTIMATE_POINTS = [1, 2, 3, 5, 8] as const;

// ── Types ─────────────────────────────────────────────────────────────────────

type ModifyField = "estimatePoints" | "chessPiece" | "rcdoNodeId";

export interface WhatIfPanelProps {
  planId: string;
  currentCommits: ReadonlyArray<CommitResponse>;
}

// ── Component ─────────────────────────────────────────────────────────────────

export function WhatIfPanel({ planId, currentCommits }: WhatIfPanelProps) {
  const api = useWhatIfApi();
  const bridge = useHostBridge();
  const userId = bridge.context.authenticatedUser.id;

  const [isExpanded, setIsExpanded] = useState(false);
  const [mutations, setMutations] = useState<WhatIfMutation[]>([]);
  const [result, setResult] = useState<WhatIfResponse | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // ── Mutation form state ───────────────────────────────────────────────────
  const [action, setAction] = useState<WhatIfMutationAction>("ADD_COMMIT");

  // ADD_COMMIT fields
  const [addTitle, setAddTitle] = useState("");
  const [addChessPiece, setAddChessPiece] = useState<string>("PAWN");
  const [addPoints, setAddPoints] = useState<string>("");

  // REMOVE_COMMIT fields
  const [removeCommitId, setRemoveCommitId] = useState<string>("");

  // MODIFY_COMMIT fields
  const [modifyCommitId, setModifyCommitId] = useState<string>("");
  const [modifyField, setModifyField] = useState<ModifyField>("estimatePoints");
  const [modifyValue, setModifyValue] = useState<string>("");

  // ── Handlers ─────────────────────────────────────────────────────────────

  const handleQueueMutation = useCallback(() => {
    if (action === "ADD_COMMIT") {
      if (!addTitle.trim()) return;
      const parsedPoints = addPoints
        ? parseInt(addPoints, 10)
        : undefined;
      const mutation: WhatIfMutation = {
        action: "ADD_COMMIT",
        title: addTitle.trim(),
        chessPiece: addChessPiece,
        ...(parsedPoints !== undefined && !isNaN(parsedPoints)
          ? { estimatePoints: parsedPoints }
          : {}),
      };
      setMutations((prev) => [...prev, mutation]);
      setAddTitle("");
      setAddPoints("");
    } else if (action === "REMOVE_COMMIT") {
      if (!removeCommitId) return;
      setMutations((prev) => [
        ...prev,
        { action: "REMOVE_COMMIT", commitId: removeCommitId },
      ]);
      setRemoveCommitId("");
    } else if (action === "MODIFY_COMMIT") {
      if (!modifyCommitId || !modifyValue.trim()) return;
      const mutation: WhatIfMutation = {
        action: "MODIFY_COMMIT",
        commitId: modifyCommitId,
        ...(modifyField === "estimatePoints"
          ? { estimatePoints: parseInt(modifyValue, 10) }
          : {}),
        ...(modifyField === "chessPiece" ? { chessPiece: modifyValue } : {}),
        ...(modifyField === "rcdoNodeId" ? { rcdoNodeId: modifyValue } : {}),
      };
      setMutations((prev) => [...prev, mutation]);
      setModifyValue("");
    }
  }, [
    action,
    addTitle,
    addChessPiece,
    addPoints,
    removeCommitId,
    modifyCommitId,
    modifyField,
    modifyValue,
  ]);

  const handleSimulate = useCallback(async () => {
    if (mutations.length === 0) return;
    setLoading(true);
    setError(null);
    setResult(null);
    try {
      const response = await api.simulate({
        planId,
        userId,
        hypotheticalChanges: mutations,
      });
      setResult(response);
    } catch {
      setError("Simulation failed. Please try again.");
    } finally {
      setLoading(false);
    }
  }, [api, planId, userId, mutations]);

  // ── Collapsed state ───────────────────────────────────────────────────────

  if (!isExpanded) {
    return (
      <Button
        variant="ghost"
        size="sm"
        onClick={() => setIsExpanded(true)}
        className="self-start text-primary hover:text-primary/80 border border-dashed border-primary/30"
        data-testid="whatif-expand-btn"
      >
        <Sparkles className="h-3.5 w-3.5 mr-1.5" aria-hidden="true" />
        🔮 What-If Planner
      </Button>
    );
  }

  // ── Expanded state ────────────────────────────────────────────────────────

  return (
    <Card data-testid="whatif-panel">
      <CardHeader>
        <CardTitle className="flex items-center gap-2 text-sm">
          <Sparkles className="h-4 w-4 text-primary" aria-hidden="true" />
          What-If Planner
        </CardTitle>
        <Button
          variant="ghost"
          size="icon"
          onClick={() => setIsExpanded(false)}
          className="h-7 w-7"
          aria-label="Collapse what-if planner"
          data-testid="whatif-collapse-btn"
        >
          <ChevronUp className="h-4 w-4" />
        </Button>
      </CardHeader>

      <CardContent className="flex flex-col gap-4">
        {/* ── Mutation form ─────────────────────────────────────────────── */}
        <div className="flex flex-col gap-3">
          {/* Action tabs */}
          <div className="flex gap-1.5" role="group" aria-label="Mutation type">
            {(
              [
                "ADD_COMMIT",
                "REMOVE_COMMIT",
                "MODIFY_COMMIT",
              ] as WhatIfMutationAction[]
            ).map((a) => (
              <Button
                key={a}
                variant={action === a ? "primary" : "secondary"}
                size="sm"
                onClick={() => setAction(a)}
                data-testid={`whatif-action-${a}`}
              >
                {a === "ADD_COMMIT"
                  ? "+ Add"
                  : a === "REMOVE_COMMIT"
                    ? "− Remove"
                    : "✎ Modify"}
              </Button>
            ))}
          </div>

          {/* ADD_COMMIT inputs */}
          {action === "ADD_COMMIT" && (
            <div className="flex flex-col gap-2">
              <input
                type="text"
                placeholder="Commit title (required)"
                value={addTitle}
                onChange={(e) => setAddTitle(e.target.value)}
                className="rounded-default border border-border px-2 py-1.5 text-sm bg-background text-foreground w-full"
                data-testid="whatif-add-title"
                aria-label="Hypothetical commit title"
              />
              <div className="flex gap-2">
                <select
                  value={addChessPiece}
                  onChange={(e) => setAddChessPiece(e.target.value)}
                  className="rounded-default border border-border px-2 py-1.5 text-sm bg-background text-foreground"
                  data-testid="whatif-add-chess"
                  aria-label="Chess piece"
                >
                  {CHESS_PIECES.map((p) => (
                    <option key={p} value={p}>
                      {p}
                    </option>
                  ))}
                </select>
                <select
                  value={addPoints}
                  onChange={(e) => setAddPoints(e.target.value)}
                  className="rounded-default border border-border px-2 py-1.5 text-sm bg-background text-foreground"
                  data-testid="whatif-add-points"
                  aria-label="Estimate points"
                >
                  <option value="">Points…</option>
                  {ESTIMATE_POINTS.map((p) => (
                    <option key={p} value={String(p)}>
                      {p} pts
                    </option>
                  ))}
                </select>
              </div>
            </div>
          )}

          {/* REMOVE_COMMIT input */}
          {action === "REMOVE_COMMIT" && (
            <select
              value={removeCommitId}
              onChange={(e) => setRemoveCommitId(e.target.value)}
              className="rounded-default border border-border px-2 py-1.5 text-sm bg-background text-foreground"
              data-testid="whatif-remove-select"
              aria-label="Select commit to remove"
            >
              <option value="">Select commit to remove…</option>
              {currentCommits.map((c) => (
                <option key={c.id} value={c.id}>
                  {c.title}
                </option>
              ))}
            </select>
          )}

          {/* MODIFY_COMMIT inputs */}
          {action === "MODIFY_COMMIT" && (
            <div className="flex flex-col gap-2">
              <select
                value={modifyCommitId}
                onChange={(e) => setModifyCommitId(e.target.value)}
                className="rounded-default border border-border px-2 py-1.5 text-sm bg-background text-foreground"
                data-testid="whatif-modify-commit-select"
                aria-label="Select commit to modify"
              >
                <option value="">Select commit to modify…</option>
                {currentCommits.map((c) => (
                  <option key={c.id} value={c.id}>
                    {c.title}
                  </option>
                ))}
              </select>
              <div className="flex gap-2">
                <select
                  value={modifyField}
                  onChange={(e) =>
                    setModifyField(e.target.value as ModifyField)
                  }
                  className="rounded-default border border-border px-2 py-1.5 text-sm bg-background text-foreground"
                  data-testid="whatif-modify-field-select"
                  aria-label="Field to modify"
                >
                  <option value="estimatePoints">Estimate Points</option>
                  <option value="chessPiece">Chess Piece</option>
                  <option value="rcdoNodeId">RCDO Node ID</option>
                </select>
                {modifyField === "estimatePoints" ? (
                  <select
                    value={modifyValue}
                    onChange={(e) => setModifyValue(e.target.value)}
                    className="rounded-default border border-border px-2 py-1.5 text-sm bg-background text-foreground"
                    data-testid="whatif-modify-value-points"
                    aria-label="New estimate points"
                  >
                    <option value="">Points…</option>
                    {ESTIMATE_POINTS.map((p) => (
                      <option key={p} value={String(p)}>
                        {p} pts
                      </option>
                    ))}
                  </select>
                ) : modifyField === "chessPiece" ? (
                  <select
                    value={modifyValue}
                    onChange={(e) => setModifyValue(e.target.value)}
                    className="rounded-default border border-border px-2 py-1.5 text-sm bg-background text-foreground"
                    data-testid="whatif-modify-value-chess"
                    aria-label="New chess piece"
                  >
                    <option value="">Piece…</option>
                    {CHESS_PIECES.map((p) => (
                      <option key={p} value={p}>
                        {p}
                      </option>
                    ))}
                  </select>
                ) : (
                  <input
                    type="text"
                    placeholder="RCDO Node ID (UUID)"
                    value={modifyValue}
                    onChange={(e) => setModifyValue(e.target.value)}
                    className="rounded-default border border-border px-2 py-1.5 text-sm bg-background text-foreground flex-1"
                    data-testid="whatif-modify-value-input"
                    aria-label="New RCDO node ID"
                  />
                )}
              </div>
            </div>
          )}

          <Button
            variant="secondary"
            size="sm"
            onClick={handleQueueMutation}
            className="self-start"
            data-testid="whatif-queue-btn"
          >
            <Plus className="h-3.5 w-3.5 mr-1" aria-hidden="true" />
            Queue Mutation
          </Button>
        </div>

        {/* ── Queued mutations list ──────────────────────────────────────── */}
        {mutations.length > 0 && (
          <div className="flex flex-col gap-1.5" data-testid="whatif-mutation-list">
            <p className="m-0 text-xs font-semibold text-muted uppercase tracking-wider">
              Queued Mutations ({mutations.length})
            </p>
            {mutations.map((m, i) => {
              const commitLabel =
                currentCommits.find((c) => c.id === m.commitId)?.title ??
                m.commitId ??
                "";
              return (
                <div
                  key={i}
                  className="flex items-center justify-between gap-2 rounded-sm border border-border px-2.5 py-1.5 text-xs"
                  data-testid={`whatif-mutation-${i}`}
                >
                  <span className="flex items-center gap-1.5 flex-1 min-w-0 truncate">
                    <Badge
                      variant="default"
                      className="text-[0.6rem] shrink-0"
                    >
                      {m.action}
                    </Badge>
                    <span className="truncate">
                      {m.action === "ADD_COMMIT" ? m.title : commitLabel}
                    </span>
                  </span>
                  <Button
                    variant="ghost"
                    size="icon"
                    onClick={() =>
                      setMutations((prev) => prev.filter((_, j) => j !== i))
                    }
                    className="h-5 w-5 shrink-0"
                    aria-label={`Remove mutation ${i + 1}`}
                    data-testid={`whatif-remove-mutation-${i}`}
                  >
                    <X className="h-3 w-3" />
                  </Button>
                </div>
              );
            })}
            <Button
              variant="ghost"
              size="sm"
              onClick={() => setMutations([])}
              className="self-start text-xs text-muted"
              data-testid="whatif-clear-mutations-btn"
            >
              Clear all
            </Button>
          </div>
        )}

        {/* ── Simulate button ────────────────────────────────────────────── */}
        <Button
          variant="primary"
          size="sm"
          onClick={() => void handleSimulate()}
          disabled={loading || mutations.length === 0}
          className="self-start"
          data-testid="whatif-simulate-btn"
        >
          {loading ? (
            <>
              <Loader2
                className="h-3.5 w-3.5 mr-1.5 animate-spin"
                aria-hidden="true"
              />
              Simulating…
            </>
          ) : (
            <>
              <Sparkles className="h-3.5 w-3.5 mr-1.5" aria-hidden="true" />
              Simulate
            </>
          )}
        </Button>

        {/* ── Error ─────────────────────────────────────────────────────── */}
        {error && (
          <div
            className="rounded-default border border-danger/30 bg-danger/5 px-3 py-2 text-xs text-danger"
            data-testid="whatif-error"
            role="alert"
          >
            {error}
          </div>
        )}

        {/* ── Results ───────────────────────────────────────────────────── */}
        {result && (
          <div className="flex flex-col gap-3 border-t border-border pt-3" data-testid="whatif-results">
            {/* Simulation unavailable */}
            {!result.available && (
              <div
                className="rounded-default border border-neutral-300 bg-neutral-100 px-3 py-2 text-xs text-muted"
                data-testid="whatif-unavailable"
              >
                Simulation is currently unavailable.
              </div>
            )}

            {result.available &&
              result.currentState &&
              result.projectedState && (
                <>
                  {/* Capacity impact */}
                  <div data-testid="whatif-capacity">
                    <p className="m-0 mb-1 text-xs font-semibold text-muted uppercase tracking-wider">
                      Capacity Impact
                    </p>
                    <div className="flex items-center gap-2 text-sm flex-wrap">
                      <span>{result.currentState.totalPoints} pts</span>
                      <span className="text-muted" aria-hidden="true">
                        →
                      </span>
                      <span
                        className={cn(
                          "font-semibold",
                          result.projectedState.totalPoints >
                            result.currentState.capacityBudget
                            ? "text-danger"
                            : "text-success",
                        )}
                      >
                        {result.projectedState.totalPoints} pts
                      </span>
                      <span className="text-xs text-muted">
                        (budget: {result.currentState.capacityBudget} pts,{" "}
                        <span
                          className={cn(
                            result.capacityDelta > 0
                              ? "text-warning"
                              : result.capacityDelta < 0
                                ? "text-success"
                                : "text-muted",
                          )}
                        >
                          {result.capacityDelta > 0 ? "+" : ""}
                          {result.capacityDelta}
                        </span>
                        )
                      </span>
                    </div>
                  </div>

                  {/* Risk delta */}
                  {result.riskDelta &&
                    (result.riskDelta.newRisks.length > 0 ||
                      result.riskDelta.resolvedRisks.length > 0) && (
                      <div data-testid="whatif-risk-delta">
                        <p className="m-0 mb-1 text-xs font-semibold text-muted uppercase tracking-wider">
                          Risk Changes
                        </p>
                        <div className="flex flex-col gap-1">
                          {result.riskDelta.newRisks.map((r) => (
                            <div
                              key={r}
                              className="flex items-center gap-1.5 text-xs text-danger"
                            >
                              <span aria-hidden="true">⚠</span>
                              <span>New:</span>
                              <Badge
                                variant="default"
                                className="text-[0.6rem] bg-danger/10 text-danger border-danger/20"
                              >
                                {r}
                              </Badge>
                            </div>
                          ))}
                          {result.riskDelta.resolvedRisks.map((r) => (
                            <div
                              key={r}
                              className="flex items-center gap-1.5 text-xs text-success"
                            >
                              <span aria-hidden="true">✓</span>
                              <span>Resolved:</span>
                              <Badge
                                variant="default"
                                className="text-[0.6rem] bg-success/10 text-success border-success/20"
                              >
                                {r}
                              </Badge>
                            </div>
                          ))}
                        </div>
                      </div>
                    )}

                  {/* RCDO coverage changes */}
                  {result.rcdoCoverageChanges &&
                    result.rcdoCoverageChanges.length > 0 && (
                      <div data-testid="whatif-coverage-changes">
                        <p className="m-0 mb-1 text-xs font-semibold text-muted uppercase tracking-wider">
                          RCDO Coverage Changes
                        </p>
                        <div className="flex flex-col gap-1">
                          {result.rcdoCoverageChanges.map((c) => (
                            <div
                              key={c.rcdoNodeId}
                              className="flex items-center gap-2 text-xs"
                            >
                              <span className="font-mono text-muted text-[0.65rem] truncate max-w-[8rem]">
                                {c.rcdoTitle ??
                                  c.rcdoNodeId.slice(0, 8) + "…"}
                              </span>
                              <span>{c.beforePoints} pts</span>
                              <span className="text-muted" aria-hidden="true">
                                →
                              </span>
                              <span
                                className={cn(
                                  "font-semibold",
                                  c.afterPoints > c.beforePoints
                                    ? "text-success"
                                    : "text-danger",
                                )}
                              >
                                {c.afterPoints} pts
                              </span>
                              <span
                                className={cn(
                                  "text-[0.65rem]",
                                  c.afterPoints > c.beforePoints
                                    ? "text-success"
                                    : "text-danger",
                                )}
                              >
                                (
                                {c.afterPoints - c.beforePoints > 0 ? "+" : ""}
                                {c.afterPoints - c.beforePoints})
                              </span>
                            </div>
                          ))}
                        </div>
                      </div>
                    )}

                  {/* AI narrative — shown only when narrative is non-null */}
                  {result.narrative && (
                    <div
                      className="rounded-default border border-primary/20 bg-primary/5 px-3 py-2.5"
                      data-testid="whatif-narrative"
                    >
                      <p className="m-0 mb-1.5 text-xs font-semibold text-primary uppercase tracking-wider flex items-center gap-1">
                        <Sparkles className="h-3 w-3" aria-hidden="true" />
                        AI Insight
                      </p>
                      <p className="m-0 text-sm leading-relaxed">
                        {result.narrative}
                      </p>
                      {result.recommendation && (
                        <p className="m-0 mt-2 text-xs text-muted italic">
                          💡 {result.recommendation}
                        </p>
                      )}
                    </div>
                  )}
                </>
              )}
          </div>
        )}
      </CardContent>
    </Card>
  );
}

/**
 * PlanHistoryView — week-by-week plan history for the current user.
 */
import { useState } from "react";
import { ChevronDown, ChevronRight } from "lucide-react";
import { Badge } from "../ui/Badge.js";
import { Button } from "../ui/Button.js";
import type { WeeklyPlanHistoryEntry } from "../../api/ticketTypes.js";
import type { PlanState } from "../../api/planTypes.js";
import { cn } from "../../lib/utils.js";

export interface PlanHistoryViewProps {
  readonly entries: WeeklyPlanHistoryEntry[];
  readonly loading: boolean;
  readonly onViewPlan?: (planId: string, weekStart: string) => void;
}

const STATE_VARIANT: Record<PlanState, "draft" | "locked" | "reconciling" | "reconciled"> = {
  DRAFT: "draft",
  LOCKED: "locked",
  RECONCILING: "reconciling",
  RECONCILED: "reconciled",
};

function formatWeekLabel(isoDate: string): string {
  const d = new Date(`${isoDate}T00:00:00`);
  return d.toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" });
}

const thCls = "px-2.5 py-2 text-left text-[0.7rem] font-bold uppercase tracking-widest text-muted border-b-2 border-border whitespace-nowrap";
const tdCls = "px-2.5 py-2 text-sm border-b border-border align-middle";

export function PlanHistoryView({ entries, loading, onViewPlan }: PlanHistoryViewProps) {
  const [expandedPlanId, setExpandedPlanId] = useState<string | null>(null);

  if (loading) {
    return (
      <div data-testid="plan-history-loading" role="status" aria-label="Loading plan history" className="text-sm text-muted">
        Loading history…
      </div>
    );
  }

  if (entries.length === 0) {
    return (
      <div data-testid="plan-history-empty" className="py-6 text-center text-sm text-muted">
        No historical plans found.
      </div>
    );
  }

  const sorted = [...entries].sort((a, b) => new Date(b.weekStartDate).getTime() - new Date(a.weekStartDate).getTime());

  return (
    <section data-testid="plan-history-view" aria-labelledby="plan-history-heading">
      <h3 id="plan-history-heading" className="m-0 mb-3 text-sm font-bold">Plan History</h3>
      <div className="overflow-x-auto">
        <table data-testid="plan-history-table" className="w-full border-collapse text-sm">
          <thead>
            <tr>
              <th className={thCls}>Week</th>
              <th className={thCls}>State</th>
              <th className={thCls}>Compliant</th>
              <th className={cn(thCls, "text-center")}>Commits</th>
              <th className={cn(thCls, "text-center")}>Planned Pts</th>
              <th className={cn(thCls, "text-center")}>Achieved Pts</th>
              <th className={cn(thCls, "text-center")}>Carry-fwd</th>
              <th className={thCls}></th>
            </tr>
          </thead>
          <tbody>
            {sorted.map((entry) => (
              <>
                <tr
                  key={entry.planId}
                  data-testid={`plan-history-row-${entry.planId}`}
                  className={cn("cursor-pointer hover:bg-background/60 transition-colors", expandedPlanId === entry.planId && "bg-background")}
                  onClick={() => setExpandedPlanId(expandedPlanId === entry.planId ? null : entry.planId)}
                >
                  <td className={tdCls}>
                    <span data-testid={`plan-history-week-${entry.planId}`}>{formatWeekLabel(entry.weekStartDate)}</span>
                  </td>
                  <td className={tdCls}>
                    <Badge variant={STATE_VARIANT[entry.planState]}>{entry.planState}</Badge>
                  </td>
                  <td className={tdCls}>
                    {entry.compliant ? (
                      <span data-testid={`plan-history-compliant-${entry.planId}`} className="font-bold text-success">✓</span>
                    ) : (
                      <span data-testid={`plan-history-noncompliant-${entry.planId}`} className="text-danger">✗</span>
                    )}
                  </td>
                  <td className={cn(tdCls, "text-center")} data-testid={`plan-history-commits-${entry.planId}`}>{entry.commitCount}</td>
                  <td className={cn(tdCls, "text-center")} data-testid={`plan-history-planned-${entry.planId}`}>{entry.plannedPoints}</td>
                  <td className={cn(tdCls, "text-center")}>
                    <span data-testid={`plan-history-achieved-${entry.planId}`} className={entry.planState === "RECONCILED" ? "text-success" : "text-muted"}>
                      {entry.achievedPoints}
                    </span>
                  </td>
                  <td className={cn(tdCls, "text-center")}>
                    {entry.carryForwardCount > 0 ? (
                      <Badge data-testid={`plan-history-cf-${entry.planId}`} variant="draft">{entry.carryForwardCount} CF</Badge>
                    ) : (
                      <span className="text-muted">—</span>
                    )}
                  </td>
                  <td className={cn(tdCls, "text-right")}>
                    {expandedPlanId === entry.planId
                      ? <ChevronDown className="h-3.5 w-3.5 text-muted inline" />
                      : <ChevronRight className="h-3.5 w-3.5 text-muted inline" />}
                  </td>
                </tr>
                {expandedPlanId === entry.planId && (
                  <tr key={`${entry.planId}-expanded`} data-testid={`plan-history-expanded-${entry.planId}`}>
                    <td colSpan={8} className="px-5 py-3 bg-background border-b border-border">
                      <div className="flex gap-4 items-center flex-wrap">
                        <span className="text-sm">
                          Week of <strong>{formatWeekLabel(entry.weekStartDate)}</strong> — <strong>{entry.planState}</strong>
                        </span>
                        {onViewPlan && (
                          <Button
                            variant="secondary"
                            size="sm"
                            onClick={(e) => { e.stopPropagation(); onViewPlan(entry.planId, entry.weekStartDate); }}
                            data-testid={`plan-history-view-btn-${entry.planId}`}
                          >
                            View Full Plan →
                          </Button>
                        )}
                      </div>
                    </td>
                  </tr>
                )}
              </>
            ))}
          </tbody>
        </table>
      </div>
    </section>
  );
}

/**
 * ScopeChangeTimeline — chronological list of all post-lock scope changes.
 */
import { cn } from "../../lib/utils.js";
import type { ScopeChangeEventResponse, ScopeChangeCategory } from "../../api/planTypes.js";

const CATEGORY_LABELS: Record<ScopeChangeCategory, string> = {
  COMMIT_ADDED: "Commit Added",
  COMMIT_REMOVED: "Commit Removed",
  ESTIMATE_CHANGED: "Estimate Changed",
  CHESS_PIECE_CHANGED: "Chess Piece Changed",
  RCDO_CHANGED: "RCDO Changed",
  PRIORITY_CHANGED: "Priority Changed",
};

const CATEGORY_CLS: Record<ScopeChangeCategory, string> = {
  COMMIT_ADDED: "bg-neutral-800",
  COMMIT_REMOVED: "bg-neutral-600",
  ESTIMATE_CHANGED: "bg-neutral-500",
  CHESS_PIECE_CHANGED: "bg-neutral-500",
  RCDO_CHANGED: "bg-neutral-400",
  PRIORITY_CHANGED: "bg-neutral-700",
};

const CATEGORY_TEXT_CLS: Record<ScopeChangeCategory, string> = {
  COMMIT_ADDED: "text-foreground font-bold",
  COMMIT_REMOVED: "text-foreground underline",
  ESTIMATE_CHANGED: "text-foreground",
  CHESS_PIECE_CHANGED: "text-foreground",
  RCDO_CHANGED: "text-muted",
  PRIORITY_CHANGED: "text-foreground",
};

const CATEGORY_ICONS: Record<ScopeChangeCategory, string> = {
  COMMIT_ADDED: "+",
  COMMIT_REMOVED: "−",
  ESTIMATE_CHANGED: "~",
  CHESS_PIECE_CHANGED: "♟",
  RCDO_CHANGED: "◎",
  PRIORITY_CHANGED: "↕",
};

export interface ScopeChangeTimelineProps {
  readonly events: ScopeChangeEventResponse[];
}

export function ScopeChangeTimeline({ events }: ScopeChangeTimelineProps) {
  if (events.length === 0) {
    return (
      <div data-testid="scope-change-timeline-empty" className="py-3 text-center text-sm text-muted">
        No scope changes recorded.
      </div>
    );
  }

  return (
    <ol data-testid="scope-change-timeline" aria-label="Scope change timeline" className="list-none m-0 p-0 flex flex-col gap-2">
      {events.map((event) => {
        const badgeCls = CATEGORY_CLS[event.category] ?? "bg-neutral-500";
        const textCls = CATEGORY_TEXT_CLS[event.category] ?? "text-foreground";
        const icon = CATEGORY_ICONS[event.category] ?? "·";
        const label = CATEGORY_LABELS[event.category] ?? event.category;
        const ts = new Date(event.createdAt).toLocaleString("en-US", { month: "short", day: "numeric", hour: "numeric", minute: "2-digit" });

        return (
          <li key={event.id} data-testid={`scope-change-event-${event.id}`}
            className="flex gap-2.5 items-start rounded-default border border-border bg-surface p-2.5">
            <span className={cn("shrink-0 h-6 w-6 rounded-full flex items-center justify-center text-xs font-bold text-background", badgeCls)} aria-hidden="true">
              {icon}
            </span>
            <div className="flex-1 min-w-0">
              <div className="flex items-center gap-2 flex-wrap">
                <span className={cn("text-xs font-semibold", textCls)}>{label}</span>
                <span className="text-xs text-muted">{ts}</span>
              </div>
              <p className="m-0 mt-1 text-xs text-muted">{event.reason}</p>
              {event.previousValue != null && event.newValue != null && (
                <div className="flex gap-1.5 mt-1 items-center text-xs flex-wrap">
                  <span className="px-1.5 py-px rounded bg-neutral-100 text-foreground line-through">{event.previousValue}</span>
                  <span className="text-muted">→</span>
                  <span className="px-1.5 py-px rounded bg-foreground/5 text-foreground font-semibold">{event.newValue}</span>
                </div>
              )}
            </div>
          </li>
        );
      })}
    </ol>
  );
}

/**
 * RCDO management page.
 * Route: /weekly/rcdos
 */
import { useState, useCallback } from "react";
import { Target } from "lucide-react";
import { Button } from "../components/ui/Button.js";
import { Input } from "../components/ui/Input.js";
import { Badge } from "../components/ui/Badge.js";
import { useHostContext } from "../host/HostProvider.js";
import { useRcdoTree, useRcdoApi } from "../api/rcdoHooks.js";
import { RcdoTreeView, type StatusFilter } from "../components/rcdo/RcdoTreeView.js";
import { RcdoBreadcrumb } from "../components/rcdo/RcdoBreadcrumb.js";
import { RcdoNodeForm } from "../components/rcdo/RcdoNodeForm.js";
import { ArchiveConfirmDialog } from "../components/rcdo/ArchiveConfirmDialog.js";
import { MoveNodeDialog } from "../components/rcdo/MoveNodeDialog.js";
import type { RcdoTreeNode, RcdoNodeType } from "../api/rcdoTypes.js";

interface RcdoPermissions {
  readonly canCreateRallyCry: boolean; readonly canEditRallyCry: boolean;
  readonly canCreateDO: boolean; readonly canEditDO: boolean;
  readonly canCreateOutcome: boolean; readonly canEditOutcome: boolean;
  readonly canArchive: boolean; readonly canMove: boolean; readonly isReadOnly: boolean;
}

function useRcdoPermissions(): RcdoPermissions {
  const { featureFlags } = useHostContext();
  const isAdmin = Boolean(featureFlags.rcdoAdminEnabled);
  const isManager = featureFlags.managerReviewEnabled;
  return {
    canCreateRallyCry: isAdmin, canEditRallyCry: isAdmin,
    canCreateDO: isAdmin || isManager, canEditDO: isAdmin || isManager,
    canCreateOutcome: isAdmin || isManager, canEditOutcome: isAdmin || isManager,
    canArchive: isAdmin || isManager, canMove: isAdmin || isManager,
    isReadOnly: !isAdmin && !isManager,
  };
}

function findNodePath(nodes: RcdoTreeNode[], targetId: string, currentPath: RcdoTreeNode[] = []): RcdoTreeNode[] {
  for (const node of nodes) {
    const path = [...currentPath, node];
    if (node.id === targetId) return path;
    const found = findNodePath(node.children, targetId, path);
    if (found.length > 0) return found;
  }
  return [];
}

function findNode(nodes: RcdoTreeNode[], targetId: string): RcdoTreeNode | null {
  for (const node of nodes) {
    if (node.id === targetId) return node;
    const found = findNode(node.children, targetId);
    if (found) return found;
  }
  return null;
}

function hasActiveChildren(node: RcdoTreeNode): boolean {
  return node.children.some((child) => child.status !== "ARCHIVED" || hasActiveChildren(child));
}

type PanelMode = "empty" | "detail" | "create" | "edit";

const STATUS_BADGE_VARIANT: Record<string, "success" | "draft" | "default"> = {
  ACTIVE: "success", DRAFT: "draft", ARCHIVED: "default",
};

export default function Rcdos() {
  const perms = useRcdoPermissions();
  const api = useRcdoApi();
  const { data: tree, loading, error, refetch } = useRcdoTree();

  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [panelMode, setPanelMode] = useState<PanelMode>("empty");
  const [createNodeType, setCreateNodeType] = useState<RcdoNodeType | null>(null);
  const [createParentId, setCreateParentId] = useState<string | null>(null);
  const [showArchiveDialog, setShowArchiveDialog] = useState(false);
  const [showMoveDialog, setShowMoveDialog] = useState(false);
  const [dialogSubmitting, setDialogSubmitting] = useState(false);
  const [actionError, setActionError] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState("");
  const [statusFilter, setStatusFilter] = useState<StatusFilter>("all");

  const nodes = tree ?? [];
  const selectedNode = selectedId ? findNode(nodes, selectedId) : null;
  const selectedPath = selectedId ? findNodePath(nodes, selectedId) : [];

  const handleSelect = useCallback((id: string) => { setSelectedId(id); setPanelMode("detail"); setActionError(null); }, []);
  const handleBreadcrumbNavigate = useCallback((id: string) => { setSelectedId(id); setPanelMode("detail"); setActionError(null); }, []);

  function openCreate(nodeType: RcdoNodeType, parentId?: string) {
    setCreateNodeType(nodeType); setCreateParentId(parentId ?? null);
    setPanelMode("create"); setActionError(null);
  }

  async function handleCreate(payload: Parameters<ReturnType<typeof useRcdoApi>["createNode"]>[0]) {
    const created = await api.createNode(payload);
    refetch(); setSelectedId(created.id); setPanelMode("detail");
  }

  function openEdit() { if (!selectedNode) return; setPanelMode("edit"); setActionError(null); }

  async function handleEdit(payload: Parameters<ReturnType<typeof useRcdoApi>["updateNode"]>[1]) {
    if (!selectedId) return;
    await api.updateNode(selectedId, payload); refetch(); setPanelMode("detail");
  }

  async function handleArchiveConfirm() {
    if (!selectedId) return;
    setDialogSubmitting(true);
    try { await api.archiveNode(selectedId); refetch(); setShowArchiveDialog(false); setPanelMode("empty"); setSelectedId(null); }
    catch (err) { setActionError(err instanceof Error ? err.message : "Archive failed"); setShowArchiveDialog(false); }
    finally { setDialogSubmitting(false); }
  }

  async function handleMoveConfirm(newParentId: string) {
    if (!selectedId) return;
    setDialogSubmitting(true);
    try { await api.moveNode(selectedId, newParentId); refetch(); setShowMoveDialog(false); setPanelMode("detail"); }
    catch (err) { setActionError(err instanceof Error ? err.message : "Move failed"); setShowMoveDialog(false); }
    finally { setDialogSubmitting(false); }
  }

  function canEditSelected(): boolean {
    if (!selectedNode) return false;
    switch (selectedNode.nodeType) {
      case "RALLY_CRY": return perms.canEditRallyCry;
      case "DEFINING_OBJECTIVE": return perms.canEditDO;
      case "OUTCOME": return perms.canEditOutcome;
    }
  }

  return (
    <div className="flex flex-col gap-4 h-full" data-testid="page-rcdos">
      {/* Page heading */}
      <div className="flex items-center justify-between flex-wrap gap-2">
        <h2 className="m-0 text-xl font-bold">RCDO Hierarchy</h2>
        {!perms.isReadOnly && (
          <div className="flex gap-2 flex-wrap">
            {perms.canCreateRallyCry && (
              <Button variant="primary" size="sm" onClick={() => openCreate("RALLY_CRY")} data-testid="create-rally-cry-btn">+ Rally Cry</Button>
            )}
            {perms.canCreateDO && (
              <Button variant="secondary" size="sm" onClick={() => openCreate("DEFINING_OBJECTIVE", selectedNode?.nodeType === "RALLY_CRY" ? selectedNode.id : undefined)} data-testid="create-do-btn">+ Defining Objective</Button>
            )}
            {perms.canCreateOutcome && (
              <Button variant="secondary" size="sm" onClick={() => openCreate("OUTCOME", selectedNode?.nodeType === "DEFINING_OBJECTIVE" ? selectedNode.id : undefined)} data-testid="create-outcome-btn">+ Outcome</Button>
            )}
          </div>
        )}
      </div>

      {/* Two-column layout */}
      <div className="grid gap-4 flex-1 min-h-0" style={{ gridTemplateColumns: "300px 1fr" }}>
        {/* Left panel */}
        <div className="rounded-default border border-border bg-surface p-4 flex flex-col gap-3 overflow-auto" aria-label="RCDO tree panel">
          <Input id="rcdo-search" label="Search" type="search" value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} placeholder="Filter by title…" aria-label="Search RCDO nodes" />

          <fieldset className="border-0 m-0 p-0">
            <legend className="text-sm font-medium mb-1.5">Show</legend>
            <div className="flex gap-3 flex-wrap">
              {(["all", "active-only", "archived-only"] as StatusFilter[]).map((value, i) => (
                <label key={value} className="flex items-center gap-1 text-sm cursor-pointer">
                  <input type="radio" name="rcdo-status-filter" value={value} checked={statusFilter === value} onChange={() => setStatusFilter(value)} />
                  {["All", "Active", "Archived"][i]}
                </label>
              ))}
            </div>
          </fieldset>

          {loading ? (
            <div role="status" aria-label="Loading RCDO hierarchy" className="text-sm text-muted px-2">Loading…</div>
          ) : error ? (
            <div role="alert" className="text-sm text-foreground font-semibold">Failed to load: {error.message}</div>
          ) : (
            <RcdoTreeView nodes={nodes} selectedId={selectedId} onSelect={handleSelect} statusFilter={statusFilter} searchQuery={searchQuery} />
          )}
        </div>

        {/* Right panel */}
        <div className="rounded-default border border-border bg-surface p-4 overflow-auto">
          {panelMode === "empty" && (
            <div className="flex flex-col items-center justify-center h-full min-h-[200px] text-muted text-center gap-2">
              <Target className="h-10 w-10 opacity-30" aria-hidden="true" />
              <p className="m-0 text-sm">Select a node from the tree to view details, or use the buttons above to create a new one.</p>
            </div>
          )}

          {panelMode === "detail" && selectedNode && (
            <div className="flex flex-col gap-4">
              <RcdoBreadcrumb path={selectedPath} onNavigate={handleBreadcrumbNavigate} />

              <div>
                <div className="flex items-center gap-2 flex-wrap">
                  <h3 className="m-0 text-lg font-semibold">{selectedNode.title}</h3>
                  <Badge variant={STATUS_BADGE_VARIANT[selectedNode.status] ?? "default"}>{selectedNode.status}</Badge>
                </div>
                <div className="text-xs text-muted mt-1">
                  {selectedNode.nodeType === "RALLY_CRY" ? "Rally Cry" : selectedNode.nodeType === "DEFINING_OBJECTIVE" ? "Defining Objective" : "Outcome"}
                </div>
              </div>

              {actionError && (
                <div role="alert" className="rounded-default border border-neutral-300 bg-neutral-100 px-3 py-2 text-sm text-foreground font-semibold">{actionError}</div>
              )}

              {!perms.isReadOnly && (
                <div className="flex gap-2 flex-wrap" data-testid="node-action-buttons">
                  {canEditSelected() && <Button variant="primary" size="sm" onClick={openEdit} data-testid="edit-node-btn">Edit</Button>}
                  {perms.canArchive && selectedNode.status !== "ARCHIVED" && (
                    <Button variant="danger" size="sm" onClick={() => setShowArchiveDialog(true)} data-testid="archive-node-btn">Archive</Button>
                  )}
                  {perms.canMove && selectedNode.nodeType !== "RALLY_CRY" && (
                    <Button variant="secondary" size="sm" onClick={() => setShowMoveDialog(true)} data-testid="move-node-btn">Move</Button>
                  )}
                </div>
              )}
              {perms.isReadOnly && <p className="text-sm text-muted italic" data-testid="readonly-label">Read-only view</p>}
              {selectedNode.children.length > 0 && (
                <div className="text-sm text-muted">{selectedNode.children.length} child node{selectedNode.children.length !== 1 ? "s" : ""}</div>
              )}
            </div>
          )}

          {panelMode === "create" && createNodeType && (
            <RcdoNodeForm mode="create" nodeType={createNodeType} {...(createParentId !== null ? { defaultParentId: createParentId } : {})} tree={nodes} onSubmit={handleCreate} onCancel={() => setPanelMode(selectedNode ? "detail" : "empty")} />
          )}

          {panelMode === "edit" && selectedNode && (
            <RcdoNodeForm mode="edit" nodeType={selectedNode.nodeType} status={selectedNode.status} initialValues={{ title: selectedNode.title }} tree={nodes} onSubmit={handleEdit} onCancel={() => setPanelMode("detail")} />
          )}
        </div>
      </div>

      {showArchiveDialog && selectedNode && (
        <ArchiveConfirmDialog nodeName={selectedNode.title} hasActiveChildren={hasActiveChildren(selectedNode)} onConfirm={handleArchiveConfirm} onCancel={() => setShowArchiveDialog(false)} submitting={dialogSubmitting} />
      )}
      {showMoveDialog && selectedNode && (
        <MoveNodeDialog nodeName={selectedNode.title} nodeType={selectedNode.nodeType} nodeId={selectedNode.id} tree={nodes} onConfirm={handleMoveConfirm} onCancel={() => setShowMoveDialog(false)} submitting={dialogSubmitting} />
      )}
    </div>
  );
}

/**
 * Tickets page — native ticket management.
 * Route: /weekly/tickets
 */
import { useState, useCallback, useMemo } from "react";
import { useSearchParams } from "react-router-dom";
import { X } from "lucide-react";
import { Button } from "../components/ui/Button.js";
import { useHostBridge } from "../host/HostProvider.js";
import { useTicketList, useTicketApi, useTicket } from "../api/ticketHooks.js";
import { useRcdoTree } from "../api/rcdoHooks.js";
import { useTeamMembers } from "../api/teamHooks.js";
import { TicketListView, type TicketSortColumn } from "../components/tickets/TicketListView.js";
import { TicketForm } from "../components/tickets/TicketForm.js";
import { TicketDetailView } from "../components/tickets/TicketDetailView.js";
import type { TicketListParams, TicketStatus, TicketPriority, CreateTicketPayload } from "../api/ticketTypes.js";
import { TICKET_STATUS_LABELS, TICKET_PRIORITY_LABELS } from "../api/ticketTypes.js";

const TICKET_STATUSES: TicketStatus[] = ["TODO", "IN_PROGRESS", "BLOCKED", "DONE", "CANCELED"];
const TICKET_PRIORITIES: TicketPriority[] = ["CRITICAL", "HIGH", "MEDIUM", "LOW"];
const PAGE_SIZE = 20;

function paramsToListParams(sp: URLSearchParams): TicketListParams & { sortBy: TicketSortColumn; sortDir: "asc" | "desc"; page: number } {
  const status = sp.get("status") as TicketStatus | null;
  const assignee = sp.get("assignee");
  const team = sp.get("team");
  const rcdo = sp.get("rcdo");
  const week = sp.get("week");
  const priority = sp.get("priority") as TicketPriority | null;
  return {
    ...(status ? { status } : {}), ...(assignee ? { assigneeUserId: assignee } : {}),
    ...(team ? { teamId: team } : {}), ...(rcdo ? { rcdoNodeId: rcdo } : {}),
    ...(week ? { targetWeek: week } : {}), ...(priority ? { priority } : {}),
    page: sp.get("page") ? Number(sp.get("page")) : 1, pageSize: PAGE_SIZE,
    sortBy: (sp.get("sortBy") as TicketSortColumn | null) ?? "updatedAt",
    sortDir: sp.get("sortDir") === "asc" ? "asc" : "desc",
  };
}

function buildRcdoLabels(nodes: ReturnType<typeof useRcdoTree>["data"]): Record<string, string> {
  const map: Record<string, string> = {};
  function traverse(ns: typeof nodes, path: string[] = []) {
    if (!ns) return;
    for (const n of ns) { const nextPath = [...path, n.title]; map[n.id] = nextPath.join(" > "); traverse(n.children, nextPath); }
  }
  traverse(nodes ?? []);
  return map;
}

const inputCls = "h-8 rounded-default border border-border bg-surface px-2.5 text-xs text-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary/50";
const labelCls = "text-[0.65rem] font-bold uppercase tracking-wider text-muted mb-0.5 block";

function TicketFilters({ params, onParamsChange, onClearFilters }: {
  params: ReturnType<typeof paramsToListParams>;
  onParamsChange: (patch: Partial<ReturnType<typeof paramsToListParams>>) => void;
  onClearFilters: () => void;
}) {
  const hasFilter = params.status ?? params.assigneeUserId ?? params.teamId ?? params.rcdoNodeId ?? params.targetWeek ?? params.priority;
  return (
    <div data-testid="ticket-filters" className="rounded-default border border-border bg-surface px-4 py-3 flex gap-3 flex-wrap items-end">
      <div className="flex flex-col">
        <label htmlFor="tf-status-filter" className={labelCls}>Status</label>
        <select id="tf-status-filter" value={params.status ?? ""} onChange={(e) => { const v = e.target.value as TicketStatus | ""; onParamsChange({ ...(v ? { status: v } : {}), page: 1 }); }} data-testid="filter-status" className={inputCls}>
          <option value="">All statuses</option>
          {TICKET_STATUSES.map((s) => <option key={s} value={s}>{TICKET_STATUS_LABELS[s]}</option>)}
        </select>
      </div>
      <div className="flex flex-col">
        <label htmlFor="tf-priority-filter" className={labelCls}>Priority</label>
        <select id="tf-priority-filter" value={params.priority ?? ""} onChange={(e) => { const v = e.target.value as TicketPriority | ""; onParamsChange({ ...(v ? { priority: v } : {}), page: 1 }); }} data-testid="filter-priority" className={inputCls}>
          <option value="">All priorities</option>
          {TICKET_PRIORITIES.map((p) => <option key={p} value={p}>{TICKET_PRIORITY_LABELS[p]}</option>)}
        </select>
      </div>
      <div className="flex flex-col">
        <label htmlFor="tf-assignee-filter" className={labelCls}>Assignee</label>
        <input id="tf-assignee-filter" type="text" placeholder="User ID…" value={params.assigneeUserId ?? ""} onChange={(e) => { const v = e.target.value; onParamsChange({ ...(v ? { assigneeUserId: v } : {}), page: 1 }); }} data-testid="filter-assignee" className={`${inputCls} min-w-[110px]`} />
      </div>
      <div className="flex flex-col">
        <label htmlFor="tf-team-filter" className={labelCls}>Team</label>
        <input id="tf-team-filter" type="text" placeholder="Team ID…" value={params.teamId ?? ""} onChange={(e) => { const v = e.target.value; onParamsChange({ ...(v ? { teamId: v } : {}), page: 1 }); }} data-testid="filter-team" className={`${inputCls} min-w-[110px]`} />
      </div>
      <div className="flex flex-col">
        <label htmlFor="tf-rcdo-filter" className={labelCls}>RCDO</label>
        <input id="tf-rcdo-filter" type="text" placeholder="RCDO node ID…" value={params.rcdoNodeId ?? ""} onChange={(e) => { const v = e.target.value; onParamsChange({ ...(v ? { rcdoNodeId: v } : {}), page: 1 }); }} data-testid="filter-rcdo" className={`${inputCls} min-w-[110px]`} />
      </div>
      <div className="flex flex-col">
        <label htmlFor="tf-week-filter" className={labelCls}>Target Week</label>
        <input id="tf-week-filter" type="date" value={params.targetWeek ?? ""} onChange={(e) => { const v = e.target.value; onParamsChange({ ...(v ? { targetWeek: v } : {}), page: 1 }); }} data-testid="filter-week" className={inputCls} />
      </div>
      {hasFilter && (
        <Button variant="secondary" size="sm" onClick={onClearFilters} data-testid="filter-clear-all" className="self-end">
          <X className="h-3 w-3" />Clear all
        </Button>
      )}
    </div>
  );
}

export default function Tickets() {
  const bridge = useHostBridge();
  const currentUserId = bridge.context.authenticatedUser.id;
  const currentTeamId = bridge.context.currentTeam?.id;

  const [searchParams, setSearchParams] = useSearchParams();
  const listParams = useMemo(() => paramsToListParams(searchParams), [searchParams]);
  const { data: rcdoTreeData } = useRcdoTree();
  const rcdoLabels = useMemo(() => buildRcdoLabels(rcdoTreeData), [rcdoTreeData]);
  const { data: ticketPage, loading: ticketsLoading, refetch: refetchTickets } = useTicketList(listParams);
  const ticketApi = useTicketApi();

  const [selectedTicketId, setSelectedTicketId] = useState<string | null>(null);
  const { data: ticketDetail, loading: detailLoading, refetch: refetchDetail } = useTicket(selectedTicketId);
  const { data: teamMembers } = useTeamMembers(currentTeamId ?? null);
  type FormMode = "create" | "create-from-commit" | null;
  const [formMode, setFormMode] = useState<FormMode>(null);
  const [formInitialValues, setFormInitialValues] = useState<Partial<CreateTicketPayload>>({});

  const updateParams = useCallback((patch: Partial<ReturnType<typeof paramsToListParams>>) => {
    setSearchParams((prev) => {
      const next = new URLSearchParams(prev);
      const merged = { ...paramsToListParams(prev), ...patch };
      const pairs: [string, string][] = [
        ...(merged.status ? [["status", merged.status] as [string, string]] : []),
        ...(merged.assigneeUserId ? [["assignee", merged.assigneeUserId] as [string, string]] : []),
        ...(merged.teamId ? [["team", merged.teamId] as [string, string]] : []),
        ...(merged.rcdoNodeId ? [["rcdo", merged.rcdoNodeId] as [string, string]] : []),
        ...(merged.targetWeek ? [["week", merged.targetWeek] as [string, string]] : []),
        ...(merged.priority ? [["priority", merged.priority] as [string, string]] : []),
        ...(merged.page && merged.page !== 1 ? [["page", String(merged.page)] as [string, string]] : []),
        ...(merged.sortBy && merged.sortBy !== "updatedAt" ? [["sortBy", merged.sortBy] as [string, string]] : []),
        ...(merged.sortDir && merged.sortDir !== "desc" ? [["sortDir", merged.sortDir] as [string, string]] : []),
      ];
      Array.from(next.keys()).forEach((k) => next.delete(k));
      pairs.forEach(([k, v]) => next.set(k, v));
      return next;
    });
  }, [setSearchParams]);

  const handleCreateTicket = useCallback(async (payload: CreateTicketPayload) => {
    await ticketApi.createTicket(payload);
    setFormMode(null); setFormInitialValues({});
    refetchTickets();
  }, [ticketApi, refetchTickets]);

  const handleStatusTransition = useCallback(async (ticketId: string, newStatus: TicketStatus) => {
    await ticketApi.transitionStatus(ticketId, newStatus, currentUserId);
    refetchDetail(); refetchTickets();
  }, [ticketApi, refetchDetail, refetchTickets, currentUserId]);

  const handleAssigneeChange = useCallback(async (ticketId: string, assigneeUserId: string) => {
    await ticketApi.updateTicket(ticketId, assigneeUserId ? { assigneeUserId } : {});
    refetchDetail(); refetchTickets();
  }, [ticketApi, refetchDetail, refetchTickets]);

  return (
    <div className="flex flex-col gap-4" data-testid="page-tickets">
      <div className="flex items-center justify-between flex-wrap gap-2">
        <h2 className="m-0 text-xl font-bold">Tickets</h2>
        <Button variant="primary" onClick={() => { setFormInitialValues({ reporterUserId: currentUserId, ...(currentTeamId ? { teamId: currentTeamId } : {}) }); setFormMode("create"); }} data-testid="create-ticket-btn">
          + Create Ticket
        </Button>
      </div>

      <TicketFilters params={listParams} onParamsChange={updateParams} onClearFilters={() => setSearchParams(new URLSearchParams())} />

      {ticketPage && (
        <div data-testid="ticket-count" className="text-sm text-muted">
          {ticketPage.total} ticket{ticketPage.total !== 1 ? "s" : ""}
        </div>
      )}

      <div className={`flex gap-4 items-start ${selectedTicketId ? "flex-nowrap" : "flex-wrap"}`}>
        <div style={{ flex: selectedTicketId ? "0 0 55%" : "1 1 100%", minWidth: 0 }}>
          <TicketListView
            tickets={ticketPage?.items ?? []}
            total={ticketPage?.total ?? 0}
            page={listParams.page ?? 1}
            pageSize={PAGE_SIZE}
            sortBy={listParams.sortBy}
            sortDir={listParams.sortDir}
            loading={ticketsLoading}
            onPageChange={(p) => updateParams({ page: p })}
            onSortChange={(col, dir) => updateParams({ sortBy: col, sortDir: dir })}
            onSelectTicket={(id) => setSelectedTicketId(id === selectedTicketId ? null : id)}
            rcdoLabels={rcdoLabels}
          />
        </div>

        {selectedTicketId && (
          <div data-testid="ticket-detail-panel" className="flex-1 min-w-[280px] sticky top-4">
            {detailLoading && <div data-testid="ticket-detail-loading" role="status" className="text-muted p-4">Loading…</div>}
            {!detailLoading && ticketDetail && (
              <TicketDetailView
                ticket={ticketDetail}
                onStatusTransition={handleStatusTransition}
                onAssigneeChange={handleAssigneeChange}
                teamMembers={teamMembers ?? []}
                {...(ticketDetail.rcdoNodeId && rcdoLabels[ticketDetail.rcdoNodeId] ? { rcdoPath: rcdoLabels[ticketDetail.rcdoNodeId] } : {})}
                onClose={() => setSelectedTicketId(null)}
                onEdit={() => {
                  setFormInitialValues({
                    title: ticketDetail.title,
                    ...(ticketDetail.description ? { description: ticketDetail.description } : {}),
                    status: ticketDetail.status, priority: ticketDetail.priority,
                    ...(ticketDetail.assigneeUserId ? { assigneeUserId: ticketDetail.assigneeUserId } : {}),
                    reporterUserId: ticketDetail.reporterUserId, teamId: ticketDetail.teamId,
                    ...(ticketDetail.rcdoNodeId ? { rcdoNodeId: ticketDetail.rcdoNodeId } : {}),
                    ...(ticketDetail.estimatePoints != null ? { estimatePoints: ticketDetail.estimatePoints } : {}),
                    ...(ticketDetail.targetWeekStartDate ? { targetWeekStartDate: ticketDetail.targetWeekStartDate } : {}),
                  });
                  setFormMode("create");
                }}
              />
            )}
          </div>
        )}
      </div>

      {formMode !== null && (
        <TicketForm
          mode="create"
          initialValues={formInitialValues}
          currentUserId={currentUserId}
          {...(currentTeamId ? { currentTeamId } : {})}
          rcdoTree={rcdoTreeData ?? []}
          onSubmit={handleCreateTicket}
          onCancel={() => { setFormMode(null); setFormInitialValues({}); }}
        />
      )}
    </div>
  );
}

/**
 * TicketListView — sortable, paginated table of tickets.
 */
import { ChevronLeft, ChevronRight, ArrowUpDown, ArrowUp, ArrowDown } from "lucide-react";
import { Button } from "../ui/Button.js";
import { Badge } from "../ui/Badge.js";
import { cn } from "../../lib/utils.js";
import type { TicketSummaryResponse, TicketStatus, TicketPriority } from "../../api/ticketTypes.js";
import { TICKET_STATUS_LABELS, TICKET_PRIORITY_LABELS } from "../../api/ticketTypes.js";

export type TicketSortColumn = "key" | "title" | "status" | "priority" | "updatedAt";

export interface TicketListViewProps {
  readonly tickets: TicketSummaryResponse[];
  readonly total: number;
  readonly page: number;
  readonly pageSize: number;
  readonly sortBy: TicketSortColumn;
  readonly sortDir: "asc" | "desc";
  readonly loading: boolean;
  readonly onPageChange: (page: number) => void;
  readonly onSortChange: (col: TicketSortColumn, dir: "asc" | "desc") => void;
  readonly onSelectTicket: (ticketId: string) => void;
  readonly rcdoLabels?: Record<string, string>;
}

const STATUS_BADGE_VARIANT: Record<TicketStatus, "default" | "primary" | "success" | "danger"> = {
  TODO: "default", IN_PROGRESS: "primary", DONE: "success", CANCELED: "default", BLOCKED: "danger",
};
const PRIORITY_BADGE_VARIANT: Record<TicketPriority, "danger" | "warning" | "primary" | "default"> = {
  CRITICAL: "danger", HIGH: "warning", MEDIUM: "primary", LOW: "default",
};

const SORTABLE_COLUMNS: { col: TicketSortColumn; label: string }[] = [
  { col: "key", label: "Key" }, { col: "title", label: "Title" },
  { col: "status", label: "Status" }, { col: "priority", label: "Priority" }, { col: "updatedAt", label: "Updated" },
];

const thCls = "px-2.5 py-2 text-left text-[0.7rem] font-bold uppercase tracking-wider text-muted border-b-2 border-border whitespace-nowrap cursor-pointer select-none hover:text-foreground transition-colors";
const tdCls = "px-2.5 py-2 text-sm border-b border-border align-middle";

export function TicketListView({ tickets, total, page, pageSize, sortBy, sortDir, loading, onPageChange, onSortChange, onSelectTicket, rcdoLabels = {} }: TicketListViewProps) {
  const totalPages = Math.max(1, Math.ceil(total / pageSize));

  function handleSortClick(col: TicketSortColumn) {
    if (sortBy === col) { onSortChange(col, sortDir === "asc" ? "desc" : "asc"); }
    else { onSortChange(col, "asc"); }
  }

  return (
    <div data-testid="ticket-list-view" className="flex flex-col gap-3">
      {loading && <div role="status" aria-label="Loading tickets" data-testid="ticket-list-loading" className="text-sm text-muted px-2">Loading tickets…</div>}

      {!loading && tickets.length === 0 && (
        <div data-testid="ticket-list-empty" className="py-8 text-center text-sm text-muted">No tickets found matching your filters.</div>
      )}

      {!loading && tickets.length > 0 && (
        <div className="overflow-x-auto">
          <table data-testid="ticket-list-table" className="w-full border-collapse text-sm">
            <thead>
              <tr>
                {SORTABLE_COLUMNS.map(({ col, label }) => (
                  <th key={col} className={thCls} onClick={() => handleSortClick(col)} data-testid={`sort-col-${col}`} aria-sort={sortBy === col ? (sortDir === "asc" ? "ascending" : "descending") : "none"}>
                    <span className="inline-flex items-center gap-1">
                      {label}
                      {sortBy === col
                        ? sortDir === "asc" ? <ArrowUp className="h-3 w-3" /> : <ArrowDown className="h-3 w-3" />
                        : <ArrowUpDown className="h-3 w-3 opacity-30" />}
                    </span>
                  </th>
                ))}
                <th className={thCls}>Assignee</th>
                <th className={thCls}>Team</th>
                <th className={thCls}>RCDO</th>
                <th className={thCls}>Target Week</th>
              </tr>
            </thead>
            <tbody>
              {tickets.map((ticket) => (
                <tr key={ticket.id} data-testid={`ticket-row-${ticket.id}`} onClick={() => onSelectTicket(ticket.id)} className="cursor-pointer hover:bg-background/80 transition-colors">
                  <td className={tdCls}><span data-testid={`ticket-key-${ticket.id}`} className="font-mono text-xs font-semibold">{ticket.key}</span></td>
                  <td className={cn(tdCls, "max-w-[250px]")}><span data-testid={`ticket-title-${ticket.id}`} className="block overflow-hidden text-ellipsis whitespace-nowrap">{ticket.title}</span></td>
                  <td className={tdCls}><Badge variant={STATUS_BADGE_VARIANT[ticket.status]}>{TICKET_STATUS_LABELS[ticket.status]}</Badge></td>
                  <td className={tdCls}><Badge variant={PRIORITY_BADGE_VARIANT[ticket.priority]}>{TICKET_PRIORITY_LABELS[ticket.priority]}</Badge></td>
                  <td className={cn(tdCls, "text-xs text-muted")}>{new Date(ticket.updatedAt).toLocaleDateString()}</td>
                  <td className={cn(tdCls, "text-xs")}>{ticket.assigneeDisplayName ?? (ticket.assigneeUserId ? ticket.assigneeUserId.slice(0, 8) + "…" : <span className="text-muted">—</span>)}</td>
                  <td className={cn(tdCls, "text-xs")}>{ticket.teamName ?? ticket.teamId.slice(0, 8) + "…"}</td>
                  <td className={cn(tdCls, "text-xs text-muted")}>{ticket.rcdoNodeId ? (rcdoLabels[ticket.rcdoNodeId] ?? ticket.rcdoNodeId) : "—"}</td>
                  <td className={cn(tdCls, "text-xs")}>{ticket.targetWeekStartDate ?? <span className="text-muted">—</span>}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {total > pageSize && (
        <div data-testid="ticket-list-pagination" className="flex items-center gap-2 justify-end flex-wrap">
          <span className="text-xs text-muted">{(page - 1) * pageSize + 1}–{Math.min(page * pageSize, total)} of {total}</span>
          <Button variant="secondary" size="sm" onClick={() => onPageChange(page - 1)} disabled={page <= 1} data-testid="ticket-page-prev">
            <ChevronLeft className="h-3.5 w-3.5" />Prev
          </Button>
          <span data-testid="ticket-page-indicator" className="text-xs">{page} / {totalPages}</span>
          <Button variant="secondary" size="sm" onClick={() => onPageChange(page + 1)} disabled={page >= totalPages} data-testid="ticket-page-next">
            Next<ChevronRight className="h-3.5 w-3.5" />
          </Button>
        </div>
      )}
    </div>
  );
}

/**
 * OverviewSection — top-level team week summary cards.
 */
import { cn } from "../../lib/utils.js";
import type { MemberComplianceSummary, MemberWeekView, ExceptionResponse, ExceptionSeverity } from "../../api/teamTypes.js";

export interface OverviewSectionProps {
  readonly complianceSummary: MemberComplianceSummary[];
  readonly memberViews: MemberWeekView[];
  readonly exceptions: ExceptionResponse[];
}

function ComplianceCard({ label, compliantCount, totalCount, testId }: { label: string; compliantCount: number; totalCount: number; testId: string }) {
  const pct = totalCount > 0 ? Math.round((compliantCount / totalCount) * 100) : 100;
  const valueCls = pct >= 80 ? "text-foreground" : pct >= 50 ? "text-muted" : "text-foreground font-black underline";

  return (
    <div data-testid={testId} className="rounded-default border border-border bg-surface p-4 flex-1 min-w-[180px]">
      <div className="text-[0.7rem] text-muted font-semibold uppercase tracking-wider mb-2">{label}</div>
      <div className={cn("text-2xl font-bold", valueCls)} data-testid={`${testId}-count`}>{compliantCount}/{totalCount}</div>
      <div className="text-xs text-muted mt-1" data-testid={`${testId}-pct`}>{pct}% on-time</div>
    </div>
  );
}

function PointsCard({ plannedPoints, achievedPoints }: { plannedPoints: number; achievedPoints: number }) {
  const delta = achievedPoints - plannedPoints;
  return (
    <div data-testid="points-summary-card" className="rounded-default border border-border bg-surface p-4 flex-1 min-w-[180px]">
      <div className="text-[0.7rem] text-muted font-semibold uppercase tracking-wider mb-2">Points</div>
      <div className="flex gap-4 items-baseline flex-wrap">
        <div>
          <span className="text-2xl font-bold" data-testid="planned-points">{plannedPoints}</span>
          <span className="text-xs text-muted ml-1">planned</span>
        </div>
        <div>
          <span className={cn("text-2xl font-bold", achievedPoints > 0 ? "text-foreground" : "text-muted")} data-testid="achieved-points">{achievedPoints}</span>
          <span className="text-xs text-muted ml-1">achieved</span>
        </div>
      </div>
      {achievedPoints > 0 && (
        <div className={cn("text-xs mt-1 font-semibold", delta >= 0 ? "text-foreground" : "text-foreground underline")} data-testid="points-delta">
          {delta >= 0 ? "+" : ""}{delta} delta
        </div>
      )}
    </div>
  );
}

const SEVERITY_BADGE: Record<ExceptionSeverity, string> = {
  HIGH: "bg-foreground text-background",
  MEDIUM: "bg-neutral-400 text-background",
  LOW: "bg-neutral-200 text-neutral-700",
};

function ExceptionsCard({ exceptions }: { exceptions: ExceptionResponse[] }) {
  const open = exceptions.filter((e) => !e.resolved);
  const highCount = open.filter((e) => e.severity === "HIGH").length;
  const medCount = open.filter((e) => e.severity === "MEDIUM").length;
  const lowCount = open.filter((e) => e.severity === "LOW").length;

  return (
    <div data-testid="exceptions-overview-card" className="rounded-default border border-border bg-surface p-4 flex-1 min-w-[180px]">
      <div className="text-[0.7rem] text-muted font-semibold uppercase tracking-wider mb-2">Open Exceptions</div>
      <div className={cn("text-2xl font-bold", open.length > 0 ? "text-foreground underline" : "text-foreground")} data-testid="open-exceptions-count">{open.length}</div>
      {open.length > 0 && (
        <div className="flex gap-1.5 mt-2 flex-wrap">
          {highCount > 0 && <span data-testid="exceptions-high-count" className={cn("text-[0.65rem] font-bold px-1.5 py-px rounded-full", SEVERITY_BADGE.HIGH)}>{highCount} HIGH</span>}
          {medCount > 0 && <span data-testid="exceptions-medium-count" className={cn("text-[0.65rem] font-bold px-1.5 py-px rounded-full", SEVERITY_BADGE.MEDIUM)}>{medCount} MED</span>}
          {lowCount > 0 && <span data-testid="exceptions-low-count" className={cn("text-[0.65rem] font-bold px-1.5 py-px rounded-full", SEVERITY_BADGE.LOW)}>{lowCount} LOW</span>}
        </div>
      )}
    </div>
  );
}

export function OverviewSection({ complianceSummary, memberViews, exceptions }: OverviewSectionProps) {
  const total = complianceSummary.length;
  const lockedCount = complianceSummary.filter((m) => m.lockCompliant).length;
  const reconciledCount = complianceSummary.filter((m) => m.reconcileCompliant).length;
  const plannedPoints = memberViews.reduce((sum, m) => sum + m.totalCommittedPoints, 0);
  const achievedPoints = memberViews.reduce((sum, m) => sum + m.commits.filter((c) => c.outcome === "ACHIEVED").reduce((s, c) => s + (c.estimatePoints ?? 0), 0), 0);

  return (
    <section aria-labelledby="overview-heading" data-testid="overview-section">
      <h3 id="overview-heading" className="m-0 mb-3 text-sm font-bold">Overview</h3>
      <div className="flex gap-3 flex-wrap">
        <ComplianceCard label="Lock Compliance" compliantCount={lockedCount} totalCount={total} testId="lock-compliance-card" />
        <ComplianceCard label="Reconcile Compliance" compliantCount={reconciledCount} totalCount={total} testId="reconcile-compliance-card" />
        <PointsCard plannedPoints={plannedPoints} achievedPoints={achievedPoints} />
        <ExceptionsCard exceptions={exceptions} />
      </div>
    </section>
  );
}
